import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import type { Asistencia } from '@/types';
import type { AsistenciaFormData } from '@/lib/validations/asistencia';

export function useAsistencia(fechaDesde?: string, fechaHasta?: string) {
    const queryClient = useQueryClient();

    const getAsistencias = useQuery({
        queryKey: ['asistencia', fechaDesde, fechaHasta],
        queryFn: async (): Promise<Asistencia[]> => {
            let query = supabase
                .from('asistencia')
                .select(`
                    *,
                    funcionarios(
                        *,
                        profiles(nombre, apellido)
                    ),
                    horarios(
                        dia_semana,
                        hora_entrada,
                        hora_salida,
                        servicios(nombre, direccion, clientes(razon_social))
                    )
                `)
                .order('fecha', { ascending: true })
                .order('funcionario_id', { ascending: true });

            if (fechaDesde && fechaHasta) {
                query = query.gte('fecha', fechaDesde).lte('fecha', fechaHasta);
            } else if (fechaDesde) {
                query = query.eq('fecha', fechaDesde);
            }

            const { data, error } = await query;
            if (error) throw new Error(error.message);
            return data as any;
        },
    });

    const createAsistencia = useMutation({
        mutationFn: async (formData: AsistenciaFormData) => {
            const { id, ...dataToInsert } = formData;
            const { data, error } = await supabase
                .from('asistencia')
                .insert(dataToInsert)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['asistencia'] });
        },
    });

    const updateAsistencia = useMutation({
        mutationFn: async ({ id, data }: { id: string; data: Partial<AsistenciaFormData> }) => {
            const { data: result, error } = await supabase
                .from('asistencia')
                .update(data)
                .eq('id', id)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return result;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['asistencia'] });
        },
    });

    const generarPlanillaDia = useMutation({
        mutationFn: async (fecha: string) => {
            const dateObj = new Date(fecha + 'T12:00:00Z');
            const diaSemana = dateObj.getUTCDay();

            const { data: horariosRaw, error: horariosErr } = await supabase
                .from('horarios')
                .select('*')
                .eq('dia_semana', diaSemana)
                .lte('vigente_desde', fecha);

            const horarios = horariosRaw?.filter(h => !h.vigente_hasta || h.vigente_hasta >= fecha);

            console.log("[generarPlanillaDia] Fecha:", fecha, "diaSemana:", diaSemana);
            console.log("[generarPlanillaDia] Horarios found from DB:", horarios?.length, horarios);

            if (horariosErr) throw new Error(horariosErr.message);
            if (!horarios || horarios.length === 0) return { count: 0 };

            const { data: existentes, error: extErr } = await supabase
                .from('asistencia')
                .select('horario_id')
                .eq('fecha', fecha);

            if (extErr) throw new Error(extErr.message);

            const existingHorariosMap = new Set(existentes?.map(e => e.horario_id));

            // Fetch certificaciones para esa fecha
            const { data: certs } = await supabase
                .from('certificaciones')
                .select('funcionario_id')
                .lte('fecha_inicio', fecha)
                .gte('fecha_fin', fecha);

            const certsSet = new Set(certs?.map(c => c.funcionario_id) || []);

            const nuevosRegistros = horarios
                .filter(h => !existingHorariosMap.has(h.id))
                .map(h => ({
                    funcionario_id: h.funcionario_id,
                    horario_id: h.id,
                    fecha: fecha,
                    estado: certsSet.has(h.funcionario_id) ? 'certificado' : 'pendiente'
                }));

            console.log("[generarPlanillaDia] Nuevos a insertar:", nuevosRegistros.length, nuevosRegistros);

            if (nuevosRegistros.length === 0) return { count: 0 };

            const { error: insErr } = await supabase
                .from('asistencia')
                .insert(nuevosRegistros);

            if (insErr) throw new Error(insErr.message);

            return { count: nuevosRegistros.length };
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['asistencia'] });
        }
    });

    // Generate sheets for an entire week range
    const generarPlanillaSemana = useMutation({
        mutationFn: async ({ desde, hasta }: { desde: string; hasta: string }) => {
            let totalCreated = 0;
            const current = new Date(desde + 'T12:00:00');
            const end = new Date(hasta + 'T12:00:00');

            while (current <= end) {
                const fechaStr = current.toISOString().split('T')[0];
                const dateObj = new Date(fechaStr + 'T12:00:00Z');
                const diaSemana = dateObj.getUTCDay();

                const { data: horariosRaw } = await supabase
                    .from('horarios')
                    .select('*')
                    .eq('dia_semana', diaSemana)
                    .lte('vigente_desde', fechaStr);

                const horarios = horariosRaw?.filter(h => !h.vigente_hasta || h.vigente_hasta >= fechaStr);

                if (horarios && horarios.length > 0) {
                    const { data: existentes } = await supabase
                        .from('asistencia')
                        .select('horario_id')
                        .eq('fecha', fechaStr);

                    const existingSet = new Set(existentes?.map(e => e.horario_id));

                    // Check certificaciones para esa fecha
                    const { data: certs } = await supabase
                        .from('certificaciones')
                        .select('funcionario_id')
                        .lte('fecha_inicio', fechaStr)
                        .gte('fecha_fin', fechaStr);
                    const certsSet = new Set(certs?.map(c => c.funcionario_id) || []);

                    const nuevos = horarios
                        .filter(h => !existingSet.has(h.id))
                        .map(h => ({
                            funcionario_id: h.funcionario_id,
                            horario_id: h.id,
                            fecha: fechaStr,
                            estado: certsSet.has(h.funcionario_id) ? 'certificado' : 'pendiente'
                        }));

                    if (nuevos.length > 0) {
                        await supabase.from('asistencia').insert(nuevos);
                        totalCreated += nuevos.length;
                    }
                }

                current.setDate(current.getDate() + 1);
            }

            return { count: totalCreated };
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['asistencia'] });
        }
    });

    return {
        getAsistencias,
        createAsistencia,
        updateAsistencia,
        generarPlanillaDia,
        generarPlanillaSemana,
    };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import type { Certificacion } from '@/types';
import type { CertificacionFormData } from '@/lib/validations/certificacion';

export function useCertificaciones(funcionarioId?: string) {
    const queryClient = useQueryClient();

    const getCertificaciones = useQuery({
        queryKey: ['certificaciones', funcionarioId],
        queryFn: async (): Promise<Certificacion[]> => {
            if (!funcionarioId) return [];
            const { data, error } = await supabase
                .from('certificaciones')
                .select('*')
                .eq('funcionario_id', funcionarioId)
                .order('fecha_inicio', { ascending: false });

            if (error) throw new Error(error.message);
            return data;
        },
        enabled: !!funcionarioId
    });

    const getAllCertificaciones = useQuery({
        queryKey: ['certificaciones', 'all'],
        queryFn: async (): Promise<Certificacion[]> => {
            const { data, error } = await supabase
                .from('certificaciones')
                .select('*')
                .order('fecha_inicio', { ascending: false });

            if (error) throw new Error(error.message);
            return data;
        }
    });

    const createCertificacion = useMutation({
        mutationFn: async (formData: CertificacionFormData) => {
            // 1. Insert into certificaciones
            const { id, ...dataToInsert } = formData;
            const { data: cert, error: certErr } = await supabase
                .from('certificaciones')
                .insert(dataToInsert)
                .select()
                .single();

            if (certErr) throw new Error(certErr.message);

            // 2. Update existing asistencia records overlapping the dates
            const { error: asistErr } = await supabase
                .from('asistencia')
                .update({ estado: 'certificado' })
                .eq('funcionario_id', formData.funcionario_id)
                .in('estado', ['pendiente', 'ausente', 'no_citado'])
                .gte('fecha', formData.fecha_inicio)
                .lte('fecha', formData.fecha_fin);

            if (asistErr) console.warn("Failed to auto-update attendance:", asistErr);

            return cert;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['certificaciones'] });
            queryClient.invalidateQueries({ queryKey: ['asistencia'] });
        },
    });

    const deleteCertificacion = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('certificaciones')
                .delete()
                .eq('id', id);

            if (error) throw new Error(error.message);
            return true;
        },
        onSuccess: () => {
             queryClient.invalidateQueries({ queryKey: ['certificaciones'] });
        }
    });

    return {
        getCertificaciones,
        getAllCertificaciones,
        createCertificacion,
        deleteCertificacion
    };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import type { Cliente } from '@/types';
import type { ClienteFormData } from '@/lib/validations/cliente';

export function useClientes() {
    const queryClient = useQueryClient();

    const getClientes = useQuery({
        queryKey: ['clientes'],
        queryFn: async (): Promise<Cliente[]> => {
            const { data, error } = await supabase
                .from('clientes')
                .select('*')
                .order('razon_social', { ascending: true });

            if (error) throw new Error(error.message);
            return data as Cliente[];
        },
    });

    const createCliente = useMutation({
        mutationFn: async (formData: ClienteFormData) => {
            const { id, ...dataToInsert } = formData;
            const payload = { ...dataToInsert, nombre: dataToInsert.razon_social };
            const { data, error } = await supabase
                .from('clientes')
                .insert(payload)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['clientes'] });
        },
    });

    const updateCliente = useMutation({
        mutationFn: async ({ id, data }: { id: string; data: Partial<ClienteFormData> }) => {
            const payload: any = { ...data };
            if (payload.razon_social) {
                payload.nombre = payload.razon_social;
            }
            const { data: result, error } = await supabase
                .from('clientes')
                .update(payload)
                .eq('id', id)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return result;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['clientes'] });
        },
    });

    return {
        getClientes,
        createCliente,
        updateCliente,
    };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import type { Factura, FacturaItem } from '@/types';
import type { FacturaFormData } from '@/lib/validations/facturacion';

export function useFacturas() {
    const queryClient = useQueryClient();

    const getFacturas = useQuery({
        queryKey: ['facturas'],
        queryFn: async (): Promise<(Factura & { items: FacturaItem[] })[]> => {
            const { data, error } = await supabase
                .from('facturas')
                .select(`
                    *,
                    clientes(razon_social, rut, direccion, email),
                    items:factura_items(
                        id,
                        servicio_id,
                        descripcion,
                        cantidad,
                        precio_unitario,
                        total,
                        servicios(nombre)
                    )
                `)
                .order('fecha_emision', { ascending: false });

            if (error) throw new Error(error.message);
            return data as any;
        },
    });

    const createFactura = useMutation({
        mutationFn: async (formData: FacturaFormData) => {
            const { items, ...facturaData } = formData;

            // Generate a unique number if not provided (fallback)
            const numero = facturaData.numero || `FAC-${Date.now()}`;

            // Create factura
            const { data: newFactura, error: facturaError } = await supabase
                .from('facturas')
                .insert([{
                    cliente_id: facturaData.cliente_id,
                    numero: numero,
                    fecha_emision: facturaData.fecha_emision,
                    fecha_vencimiento: facturaData.fecha_vencimiento || null,
                    periodo: facturaData.periodo || null,
                    estado: facturaData.estado,
                    subtotal: facturaData.subtotal,
                    impuesto: facturaData.impuesto,
                    descuento: facturaData.descuento,
                    total: facturaData.total
                }])
                .select()
                .single();

            if (facturaError) throw new Error(`Error factura: ${facturaError.message}`);

            // Insert items
            if (items && items.length > 0) {
                const itemsToInsert = items.map(item => ({
                    factura_id: newFactura.id,
                    servicio_id: item.servicio_id || null,
                    descripcion: item.descripcion,
                    cantidad: item.cantidad,
                    precio_unitario: item.precio_unitario,
                    total: item.cantidad * item.precio_unitario
                }));

                const { error: itemsError } = await supabase
                    .from('factura_items')
                    .insert(itemsToInsert);

                if (itemsError) throw new Error(`Error items: ${itemsError.message}`);
            }

            return newFactura;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['facturas'] });
        },
    });

    const updateFacturaStatus = useMutation({
        mutationFn: async ({ id, estado }: { id: string, estado: Factura['estado'] }) => {
            const { data, error } = await supabase
                .from('facturas')
                .update({ estado, updated_at: new Date().toISOString() })
                .eq('id', id)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['facturas'] });
        }
    });

    return {
        getFacturas,
        createFactura,
        updateFacturaStatus
    };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import type { Funcionario } from '@/types';
import type { FuncionarioFormData } from '@/lib/validations/funcionario';
import { createClient } from '@supabase/supabase-js';
import { generateSecureRandomString } from '@/lib/utils';
import { toast } from 'sonner';

// Special client that doesn't persist session, so admin can create users without being logged out
const authClient = createClient(
    import.meta.env.VITE_SUPABASE_URL || 'https://placeholder-url.supabase.co',
    import.meta.env.VITE_SUPABASE_ANON_KEY || 'placeholder-key',
    { auth: { persistSession: false, autoRefreshToken: false } }
);

export function useFuncionarios() {
    const queryClient = useQueryClient();

    const getFuncionarios = useQuery({
        queryKey: ['funcionarios'],
        queryFn: async (): Promise<Funcionario[]> => {
            const { data, error } = await supabase
                .from('funcionarios')
                .select(`
          *,
          profiles(*),
          departamentos(nombre)
        `)
                .order('fecha_ingreso', { ascending: false });

            if (error) throw new Error(error.message);
            return data as any;
        },
    });

    const getDepartamentos = useQuery({
        queryKey: ['departamentos'],
        queryFn: async () => {
            const { data, error } = await supabase.from('departamentos').select('*');
            if (error) throw new Error(error.message);
            return data;
        },
    });

    const createDepartamento = useMutation({
        mutationFn: async (nombre: string) => {
            const { data, error } = await supabase.from('departamentos').insert({ nombre }).select().single();
            if (error) throw new Error(error.message);
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['departamentos'] });
        },
    });

    const createFuncionario = useMutation({
        mutationFn: async (formData: FuncionarioFormData) => {
            const tid = toast.loading('1/5 Iniciando creación...');
            let currentStep = '1/5 Iniciando creación...';
            
            // Start actual process with an internal timeout race
            const processPromise = (async () => {
                console.log("[useFuncionarios] Starting createFuncionario at", new Date().toISOString(), "Data:", formData);
                let profileId = formData.id; // if it already exists

                const randomSuffix = generateSecureRandomString(6);
                const safeEmail = formData.email?.trim() || `ci_${formData.cedula.replace(/\D/g, '')}_${randomSuffix}@soclean.internal`;
                const safePassword = formData.password?.trim() || `SC${formData.cedula.replace(/\D/g, '')}#2026`;

                // 1. Create Auth User if it's new
                if (!profileId) {
                    currentStep = '2/5 Buscando perfil existente...';
                    toast.loading(currentStep, { id: tid });
                    console.log("[useFuncionarios] No profileId, creating Auth. SafeEmail:", safeEmail);
                    // Check if profile exists (recovery mode)
                    const { data: existingProfile } = await supabase
                        .from('profiles')
                        .select('id')
                        .eq('email', safeEmail)
                        .maybeSingle();

                    console.log("[useFuncionarios] existingProfile check done:", existingProfile);

                    if (existingProfile) {
                        currentStep = '2/5 Validando funcionario existente...';
                        toast.loading(currentStep, { id: tid });
                        console.log("[useFuncionarios] Profile exists, checking funcionario...");
                        // Check if they already have a funcionario
                        const { data: existingFunc } = await supabase
                            .from('funcionarios')
                            .select('id, profiles(nombre, apellido)')
                            .eq('profile_id', existingProfile.id)
                            .maybeSingle();

                        console.log("[useFuncionarios] existingFunc check done:", existingFunc);

                        if (existingFunc) {
                            const prof = existingFunc.profiles as any;
                            const fullName = prof ? `${prof.nombre} ${prof.apellido}` : 'un funcionario activo';
                            throw new Error(`Este correo/cédula ya está registrado y asignado a ${fullName}.`);
                        }

                        // Recover the existing profile ID
                        profileId = existingProfile.id;
                    } else {
                        currentStep = '2/5 Registrando cuenta (Auth)...';
                        toast.loading(currentStep, { id: tid });
                        console.log("[useFuncionarios] Calling authClient.auth.signUp...");
                        const { data: authData, error: authError } = await authClient.auth.signUp({
                            email: safeEmail,
                            password: safePassword,
                            options: {
                                data: {
                                    nombre: formData.nombre,
                                    apellido: formData.apellido,
                                }
                            }
                        });

                        console.log("[useFuncionarios] authClient.auth.signUp finished. Error:", authError?.message, "Data:", !!authData?.user);
                        if (authError) throw new Error(`Auth Error: ${authError.message}`);
                        if (authData.user && authData.user.identities && authData.user.identities.length === 0) {
                            throw new Error('La cuenta ya existe o está en estado de protección (Intente de nuevo en unos minutos o reintente).');
                        }

                        profileId = authData.user?.id;
                    }
                }

                if (!profileId) {
                    toast.error('Fallo al crear ID de perfil', { id: tid });
                    throw new Error('Fallo al crear ID de perfil');
                }

                currentStep = '3/5 Sincronizando Perfil de usuario...';
                toast.loading(currentStep, { id: tid });
                console.log("[useFuncionarios] Calling profiles upsert for ID:", profileId);
                // 2. Upsert Role securely (Creates it if the DB trigger failed or doesn't exist)
                const { error: profileError } = await supabase
                    .from('profiles')
                    .upsert({
                        id: profileId,
                        email: safeEmail,
                        rol: formData.rol,
                        nombre: formData.nombre,
                        apellido: formData.apellido
                    }, { onConflict: 'id' });

                console.log("[useFuncionarios] profiles upsert finished. Error:", profileError?.message);
                if (profileError) {
                    toast.error(`Error Perfil: ${profileError.message}`, { id: tid });
                    throw new Error(`Profile Error: ${profileError.message}`);
                }

                currentStep = '4/5 Creando Ficha de Funcionario...';
                toast.loading(currentStep, { id: tid });
                console.log("[useFuncionarios] Calling funcionarios insert");
                // 3. Create Funcionario record
                const { data: funcData, error: funcError } = await supabase
                    .from('funcionarios')
                    .insert({
                        profile_id: profileId,
                        cedula: formData.cedula,
                        cargo: formData.cargo,
                        departamento_id: formData.departamento_id,
                        direccion: formData.direccion,
                        fecha_ingreso: formData.fecha_ingreso,
                        tipo_contrato: formData.tipo_contrato,
                        salario_base: 0,
                        estado: formData.estado,
                    })
                    .select()
                    .single();

                console.log("[useFuncionarios] funcionarios insert finished. Error:", funcError?.message, "Result OK:", !!funcData);
                if (funcError) {
                    toast.error(`Error Funcionario: ${funcError.message}`, { id: tid });
                    throw new Error(funcError.message);
                }
                
                toast.success('5/5 Operación exitosa!', { id: tid });
                return funcData;
            })();

            const internalTimeout = new Promise<never>((_, reject) => 
                setTimeout(() => reject(new Error(`Timeout interno. Se colgó en el paso: [${currentStep}]`)), 18000)
            );

            return Promise.race([processPromise, internalTimeout]);
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['funcionarios'] });
        },
    });

    const updateFuncionario = useMutation({
        mutationFn: async ({ id, data }: { id: string; data: Partial<FuncionarioFormData> }) => {
            // 1. Get the actual funcionario row to find profile_id
            const { data: funcData, error: fetchErr } = await supabase.from('funcionarios').select('profile_id').eq('id', id).single();
            if (fetchErr) throw new Error(fetchErr.message);

            // 2. Update profile data
            if (data.nombre || data.apellido || data.rol) {
                await supabase
                    .from('profiles')
                    .update({
                        nombre: data.nombre,
                        apellido: data.apellido,
                        rol: data.rol
                    })
                    .eq('id', funcData.profile_id);
            }

            // 3. Update Funcionario data
            const updateData = { ...data };
            delete updateData.nombre;
            delete updateData.apellido;
            delete updateData.email;
            delete updateData.password;
            delete updateData.rol;

            const { data: result, error } = await supabase
                .from('funcionarios')
                .update(updateData)
                .eq('id', id)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return result;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['funcionarios'] });
        },
    });

    const resetPassword = useMutation({
        mutationFn: async ({ profileId, newPassword }: { profileId: string; newPassword: string }) => {
            const { error } = await supabase.rpc('reset_user_password', {
                target_user_id: profileId,
                new_password: newPassword
            });
            if (error) throw new Error(error.message);
            return true;
        }
    });

    return {
        getFuncionarios,
        getDepartamentos,
        createDepartamento,
        createFuncionario,
        updateFuncionario,
        resetPassword,
    };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import type { Horario } from '@/types';
import type { HorarioFormData } from '@/lib/validations/horario';

export function useHorarios() {
    const queryClient = useQueryClient();

    const getHorarios = useQuery({
        queryKey: ['horarios'],
        queryFn: async (): Promise<Horario[]> => {
            const { data, error } = await supabase
                .from('horarios')
                .select(`
                    *,
                    funcionarios(
                        *,
                        profiles(nombre, apellido)
                    ),
                    servicios(
                        nombre,
                        direccion,
                        clientes(razon_social, nombre_fantasia)
                    )
                `)
                .order('dia_semana', { ascending: true })
                .order('hora_entrada', { ascending: true });

            if (error) throw new Error(error.message);
            return data as any;
        },
    });

    // Helper: check if a time range overlaps with existing schedules for the same funcionario + day
    async function checkOverlap(
        funcionarioId: string,
        diaSemana: number,
        horaEntrada: string,
        horaSalida: string,
        excludeId?: string
    ) {
        // Fetch all active schedules for this employee on this day
        let query = supabase
            .from('horarios')
            .select('id, hora_entrada, hora_salida')
            .eq('funcionario_id', funcionarioId)
            .eq('dia_semana', diaSemana)
            .is('vigente_hasta', null); // only active/indefinite schedules

        if (excludeId) {
            query = query.neq('id', excludeId);
        }

        const { data: existing, error } = await query;
        if (error) throw new Error(error.message);
        if (!existing || existing.length === 0) return; // No conflicts

        // Convert "HH:MM" to minutes for easy comparison
        const toMin = (t: string) => {
            const [h, m] = t.split(':').map(Number);
            return h * 60 + (m || 0);
        };

        const newStart = toMin(horaEntrada);
        const newEnd = toMin(horaSalida);

        for (const ex of existing) {
            const exStart = toMin(ex.hora_entrada);
            const exEnd = toMin(ex.hora_salida);

            // Two ranges overlap if one starts before the other ends and vice versa
            if (newStart < exEnd && newEnd > exStart) {
                const dias = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];
                throw new Error(
                    `⚠️ Conflicto: Este funcionario ya tiene un horario el ${dias[diaSemana]} de ${ex.hora_entrada.substring(0, 5)} a ${ex.hora_salida.substring(0, 5)} que se superpone con ${horaEntrada.substring(0, 5)}-${horaSalida.substring(0, 5)}.`
                );
            }
        }
    }

    const createHorario = useMutation({
        mutationFn: async (formData: HorarioFormData) => {
            const { id, ...dataToInsert } = formData;

            // Check for overlapping schedules BEFORE inserting
            await checkOverlap(
                dataToInsert.funcionario_id,
                dataToInsert.dia_semana,
                dataToInsert.hora_entrada,
                dataToInsert.hora_salida
            );

            const payload = {
                ...dataToInsert,
                vigente_hasta: dataToInsert.vigente_hasta || null
            };

            const { data, error } = await supabase
                .from('horarios')
                .insert(payload)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['horarios'] });
        },
    });

    const updateHorario = useMutation({
        mutationFn: async ({ id, data }: { id: string; data: Partial<HorarioFormData> }) => {
            // Check for overlapping schedules BEFORE updating (exclude current record)
            if (data.funcionario_id && data.dia_semana !== undefined && data.hora_entrada && data.hora_salida) {
                await checkOverlap(
                    data.funcionario_id,
                    data.dia_semana,
                    data.hora_entrada,
                    data.hora_salida,
                    id
                );
            }

            const payload = {
                ...data,
                vigente_hasta: data.vigente_hasta || null
            };

            const { data: result, error } = await supabase
                .from('horarios')
                .update(payload)
                .eq('id', id)
                .select()
                .single();

            if (error) throw new Error(error.message);
            return result;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['horarios'] });
        },
    });

    const deleteHorario = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('horarios')
                .delete()
                .eq('id', id);

            if (error) throw new Error(error.message);
            return id;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['horarios'] });
        },
    });

    return {
        getHorarios,
        createHorario,
        updateHorario,
        deleteHorario
    };
}

