                                    ))
                                ) : (
                                    // SINGLE DAY VIEW
                                    filteredAsistencias.map((a: Asistencia) => (
                                        <TableRow key={a.id} className="group hover:bg-muted/30 transition-colors">
                                            <TableCell>
