                    </Card>
                </div>
            )}
        </div>
    );
}

import { useState } from 'react';
import { FuncionarioFormDialog } from '@/components/funcionarios/FuncionarioFormDialog';
import { FuncionarioBulkImportDialog } from '@/components/funcionarios/FuncionarioBulkImportDialog';
import { useFuncionarios } from '@/hooks/useFuncionarios';
import type { Funcionario } from '@/types';
import { FuncionariosHeader } from '@/components/funcionarios/FuncionariosHeader';
import { FuncionariosTable } from '@/components/funcionarios/FuncionariosTable';
import { FuncionarioCertificacionesDialog } from '@/components/funcionarios/FuncionarioCertificacionesDialog';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';

export default function Employees() {
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingFuncionario, setEditingFuncionario] = useState<Funcionario | null>(null);
    const [isBulkOpen, setIsBulkOpen] = useState(false);

    const [resetDialogOpen, setResetDialogOpen] = useState(false);
    const [funcionarioToReset, setFuncionarioToReset] = useState<Funcionario | null>(null);

    const [certDialogOpen, setCertDialogOpen] = useState(false);
    const [funcionarioToCert, setFuncionarioToCert] = useState<Funcionario | null>(null);

    const { getFuncionarios, resetPassword } = useFuncionarios();
    const { data: employees = [], isLoading } = getFuncionarios;

    const handleEdit = (funcionario: Funcionario) => {
        setEditingFuncionario(funcionario);
        setIsDialogOpen(true);
    };

    const handleResetPasswordClick = (funcionario: Funcionario) => {
        setFuncionarioToReset(funcionario);
        setResetDialogOpen(true);
    };

    const handleCertificacionesClick = (funcionario: Funcionario) => {
        setFuncionarioToCert(funcionario);
        setCertDialogOpen(true);
    };

    const confirmResetPassword = async () => {
        if (!funcionarioToReset || !funcionarioToReset.profile_id) return;

        try {
            // Se usa la cédula como nueva clave estándar (limpiando puntos y guiones por seguridad básica)
            const cleanCedula = funcionarioToReset.cedula.replace(/[^0-9]/g, '');
            const newPassword = `SC${cleanCedula}#2026`; // Ej: SC12345678#2026

            await resetPassword.mutateAsync({
                profileId: funcionarioToReset.profile_id,
                newPassword: newPassword
            });

            toast.success(`Contraseña de ${funcionarioToReset.profiles?.nombre} reseteada a: ${newPassword}`);
            setResetDialogOpen(false);
            setFuncionarioToReset(null);
        } catch (error: any) {
            toast.error(error.message || 'No se pudo resetear la contraseña');
        }
    };

    const handleAddNew = () => {
        setEditingFuncionario(null);
        setIsDialogOpen(true);
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <FuncionariosHeader
                onBulkImport={() => setIsBulkOpen(true)}
                onAddNew={handleAddNew}
            />

            <FuncionariosTable
                employees={employees}
                isLoading={isLoading}
                onEdit={handleEdit}
                onResetPassword={handleResetPasswordClick}
                onCertificaciones={handleCertificacionesClick}
            />

            <FuncionarioFormDialog
                open={isDialogOpen}
                onOpenChange={setIsDialogOpen}
                funcionarioToEdit={editingFuncionario}
            />

            <FuncionarioBulkImportDialog
                open={isBulkOpen}
                onOpenChange={setIsBulkOpen}
            />

            <FuncionarioCertificacionesDialog 
                open={certDialogOpen}
                onOpenChange={setCertDialogOpen}
                funcionario={funcionarioToCert}
            />

            {/* Dialogo de Confirmación de Reseteo de Clave */}
            <Dialog open={resetDialogOpen} onOpenChange={setResetDialogOpen}>
                <DialogContent className="sm:max-w-md">
                    <DialogHeader>
                        <DialogTitle>Forzar Reseteo de Contraseña</DialogTitle>
                        <DialogDescription>
                            Estás a punto de resetear la contraseña de <strong>{funcionarioToReset?.profiles?.nombre} {funcionarioToReset?.profiles?.apellido}</strong>.
                        </DialogDescription>
                    </DialogHeader>

                    <div className="bg-amber-50 dark:bg-amber-900/20 text-amber-800 dark:text-amber-400 p-4 border border-amber-200 dark:border-amber-800 rounded-md text-sm mt-2 mb-4">
                        Esto invalidará su sesión actual y su contraseña pasará a ser el estándar de alta inicial basada en su documento (ej. <strong>SC12345678#2026</strong>). Podrás indicarle manualmente cuál es su nueva clave para que vuelva a entrar de inmediato.
                    </div>

                    <DialogFooter className="sm:justify-end gap-2">
                        <Button type="button" variant="outline" onClick={() => setResetDialogOpen(false)}>
                            Cancelar Operación
                        </Button>
                        <Button
                            type="button"
                            className="bg-amber-600 hover:bg-amber-700 text-white"
                            onClick={confirmResetPassword}
                            disabled={resetPassword.isPending}
                        >
                            {resetPassword.isPending ? 'Aplicando...' : 'Confirmar Reseteo'}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { zodResolver } from '@hookform/resolvers/zod';
import { supabase } from '@/lib/supabase';
import { useAuthStore } from '@/stores/authStore';
import { useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';
import { APP_VERSION, APP_COPYRIGHT, APP_DEVELOPER } from '@/lib/appInfo';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';

const loginSchema = z.object({
    email: z.string().email('Debe ser un correo electrónico válido'),
    password: z.string().min(6, 'La contraseña debe tener al menos 6 caracteres'),
});

type LoginForm = z.infer<typeof loginSchema>;

export default function Login() {
    const [error, setError] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    // Forgot password state
    const [isResetOpen, setIsResetOpen] = useState(false);
    const [resetEmail, setResetEmail] = useState('');
    const [isResetting, setIsResetting] = useState(false);

    const setUser = useAuthStore((state) => state.setUser);
    const setRole = useAuthStore((state) => state.setRole);
    const navigate = useNavigate();

    const {
        register,
        handleSubmit,
        formState: { errors },
    } = useForm<LoginForm>({
        resolver: zodResolver(loginSchema),
    });

    const onSubmit = async (data: LoginForm) => {
        setIsLoading(true);
        setError(null);
        try {
            const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
                email: data.email,
                password: data.password,
            });

            if (authError) throw authError;

            if (authData.user) {
                // Fetch role from profiles table
                const { data: profileData, error: profileError } = await supabase
                    .from('profiles')
                    .select('rol')
                    .eq('id', authData.user.id)
                    .single();

                if (!profileError && profileData) {
                    setRole(profileData.rol);
                }

                setUser(authData.user);
                navigate('/'); // Redirect to dashboard
            }
        } catch (err: any) {
            setError(err.message || 'Error al iniciar sesión');
        } finally {
            setIsLoading(false);
        }
    };

    const handleResetPassword = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!resetEmail) return;
        setIsResetting(true);
        try {
            const { error } = await supabase.auth.resetPasswordForEmail(resetEmail, {
                redirectTo: window.location.origin,
            });
            if (error) throw error;
            toast.success('Se ha enviado un correo con las instrucciones para restablecer tu contraseña. Revisa tu bandeja de entrada o spam.');
            setIsResetOpen(false);
            setResetEmail('');
        } catch (err: any) {
            toast.error(err.message || 'Error al enviar el correo de recuperación');
        } finally {
            setIsResetting(false);
        }
    };

    return (
        <div className="flex h-screen items-center justify-center bg-slate-50 dark:bg-slate-900 border-2">
            <div className="absolute inset-0 bg-gradient-to-br from-primary/20 via-background to-secondary/20 pointer-events-none" />
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-md">
                <div className="text-center mb-8 animate-in slide-in-from-bottom-5 duration-500">
                    <img src="/soclean-logo.png" alt="Soclean Logo" className="mx-auto h-24 max-w-[320px] mb-2 object-contain drop-shadow-md rounded-2xl" />
                </div>
                <Card className="shadow-2xl border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md animate-in zoom-in-95 duration-500 delay-150 fill-mode-backwards w-full">
                    <CardHeader className="space-y-1">
                        <CardTitle className="text-2xl text-center">Bienvenido de nuevo</CardTitle>
                        <CardDescription className="text-center">
                            Ingresa tu correo electrónico y contraseña
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                            <div className="space-y-2">
                                <Label htmlFor="email">Correo electrónico</Label>
                                <Input
                                    id="email"
                                    type="email"
                                    placeholder="nombre@empresa.com"
                                    {...register('email')}
                                    disabled={isLoading}
                                    className="bg-background/50 focus:bg-background transition-colors"
                                />
                                {errors.email && (
                                    <p className="text-sm font-medium text-destructive">{errors.email.message}</p>
                                )}
                            </div>
                            <div className="space-y-2">
                                <div className="flex items-center justify-between">
                                    <Label htmlFor="password">Contraseña</Label>
                                    <button
                                        type="button"
                                        onClick={() => setIsResetOpen(true)}
                                        className="text-sm text-primary hover:underline hover:text-primary/80 transition-colors"
                                    >
                                        ¿Olvidaste tu contraseña?
                                    </button>
                                </div>
                                <Input
                                    id="password"
                                    type="password"
                                    {...register('password')}
                                    disabled={isLoading}
                                    className="bg-background/50 focus:bg-background transition-colors"
                                />
                                {errors.password && (
                                    <p className="text-sm font-medium text-destructive">{errors.password.message}</p>
                                )}
                            </div>

                            {error && (
                                <div className="p-3 bg-destructive/15 text-destructive text-sm rounded-md border border-destructive/20 text-center">
                                    {error}
                                </div>
                            )}

                            <Button type="submit" className="w-full h-11 text-md shadow-md mt-4" disabled={isLoading}>
                                {isLoading ? 'Iniciando sesión...' : 'Iniciar Sesión'}
                            </Button>
                        </form>
                    </CardContent>
                </Card>
            </div>

            <Dialog open={isResetOpen} onOpenChange={setIsResetOpen}>
                <DialogContent className="sm:max-w-md">
                    <form onSubmit={handleResetPassword}>
                        <DialogHeader>
                            <DialogTitle>Restablecer Contraseña</DialogTitle>
                            <DialogDescription>
                                Ingresa el correo electrónico asociado a tu cuenta y te enviaremos un enlace para crear una nueva contraseña.
                            </DialogDescription>
                        </DialogHeader>

                        <div className="py-4 space-y-4">
                            <div className="space-y-2">
                                <Label htmlFor="reset-email">Correo electrónico</Label>
                                <Input
                                    id="reset-email"
                                    type="email"
                                    placeholder="nombre@empresa.com"
                                    value={resetEmail}
                                    onChange={(e) => setResetEmail(e.target.value)}
                                    required
                                    disabled={isResetting}
                                />
                            </div>
                        </div>

                        <DialogFooter>
                            <Button type="button" variant="outline" onClick={() => setIsResetOpen(false)}>
                                Cancelar
                            </Button>
                            <Button type="submit" disabled={isResetting || !resetEmail}>
                                {isResetting ? 'Enviando...' : 'Enviar correo'}
                            </Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>

            {/* Developer Credit */}
            <div className="fixed bottom-4 left-0 right-0 text-center z-10">
                <p className="text-xs text-muted-foreground/60">
                    Desarrollado por <span className="font-semibold text-muted-foreground/80">{APP_DEVELOPER}</span>
                </p>
                <p className="text-[10px] text-muted-foreground/40 mt-0.5">
                    {APP_COPYRIGHT} · v{APP_VERSION}
                </p>
            </div>
        </div>
    );
}

import { useState, useMemo, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Map, MapPin, User, Navigation, Loader2 } from 'lucide-react';
import { useServicios } from '@/hooks/useServicios';
import { useFuncionarios } from '@/hooks/useFuncionarios';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { GoogleMap, useJsApiLoader, DirectionsRenderer, Marker } from '@react-google-maps/api';

const LIBRARIES: ("places" | "geometry" | "drawing" | "visualization" | "routes")[] = ['places', 'routes'];
const MVD_CENTER = { lat: -34.9011, lng: -56.1645 };

export default function LogisticsMap() {
    const { getServicios } = useServicios();
    const { data: servicios = [] } = getServicios;
    const { getFuncionarios } = useFuncionarios();
    const { data: funcionarios = [] } = getFuncionarios;

    const [selectedServiceId, setSelectedServiceId] = useState<string>('');
    const [selectedFuncionarioId, setSelectedFuncionarioId] = useState<string>('');
    const [directionsMode, setDirectionsMode] = useState<'DRIVING' | 'TRANSIT'>('TRANSIT');
    const [directionsResponse, setDirectionsResponse] = useState<google.maps.DirectionsResult | null>(null);
    const [distance, setDistance] = useState('');
    const [duration, setDuration] = useState('');
    const [serviceMarkers, setServiceMarkers] = useState<{id: string, lat: number, lng: number, title: string}[]>([]);

    const { isLoaded, loadError } = useJsApiLoader({
        googleMapsApiKey: import.meta.env.VITE_GOOGLE_MAPS_API_KEY || '',
        libraries: LIBRARIES,
    });

    const selectedService = servicios.find(s => s.id === selectedServiceId);
    const selectedFuncionario = funcionarios.find(f => f.id === selectedFuncionarioId);

    const activeServices = useMemo(() => servicios.filter(s => s.estado === 'activo'), [servicios]);
    const activeFuncionarios = useMemo(() => funcionarios.filter(f => f.estado === 'activo'), [funcionarios]);

    const [hasAttemptedGeocode, setHasAttemptedGeocode] = useState(false);

    // Geocode active services to place green markers on the map
    useEffect(() => {
        if (!isLoaded || activeServices.length === 0 || serviceMarkers.length > 0 || hasAttemptedGeocode) return;
        
        setHasAttemptedGeocode(true); // Prevent re-runs if it fails or returns empty
        
        const geocoder = new window.google.maps.Geocoder();
        const fetchGeocodes = async () => {
            const newMarkers: any[] = [];
            for (const s of activeServices) {
                try {
                    const res = await geocoder.geocode({ address: `${s.direccion}, Montevideo, Uruguay` });
                    if (res.results && res.results[0]) {
                        newMarkers.push({
                            id: s.id,
                            title: `${s.clientes?.razon_social || ''} - ${s.nombre}`,
                            lat: res.results[0].geometry.location.lat(),
                            lng: res.results[0].geometry.location.lng()
                        });
                    }
                } catch (error) {
                    console.log(`Geocoding error for ${s.direccion}`, error);
                }
            }
            if (newMarkers.length > 0) {
                setServiceMarkers(newMarkers);
            }
        };
        fetchGeocodes();
    }, [isLoaded, activeServices, serviceMarkers.length, hasAttemptedGeocode]);

    const handleGenerateRoute = async () => {
        if (!selectedService || !selectedFuncionario || !isLoaded) return;
        
        const google = window.google;
        const directionsService = new google.maps.DirectionsService();

        try {
            const results = await directionsService.route({
                origin: `${selectedFuncionario.direccion}, Montevideo, Uruguay`,
                destination: `${selectedService.direccion}, Montevideo, Uruguay`,
                travelMode: google.maps.TravelMode[directionsMode] || google.maps.TravelMode.TRANSIT,
            });
            setDirectionsResponse(results);
            if (results.routes[0]?.legs[0]) {
                setDistance(results.routes[0].legs[0].distance?.text || '');
                setDuration(results.routes[0].legs[0].duration?.text || '');
            }
        } catch (error) {
            console.error("Error al calcular ruta:", error);
        }
    };

    const handleOpenExternalRoute = () => {
        if (!selectedService || !selectedFuncionario) return;
        const origin = encodeURIComponent(`${selectedFuncionario.direccion}, Montevideo`);
        const destination = encodeURIComponent(`${selectedService.direccion}, Montevideo`);
        // Open google maps directions specifying transit (buses) to show full transit options
        window.open(`https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${destination}&travelmode=transit`, '_blank');
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500 max-w-7xl mx-auto">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-primary flex items-center gap-2">
                        <Map className="h-8 w-8" />
                        Logística y Rutas
                    </h2>
                    <p className="text-muted-foreground text-sm mt-1">Asigna funcionarios a locaciones y asístelos en su trayecto hacia cada servicio.</p>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Left Panel - Selection Controls */}
                <div className="space-y-6">
                    <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm">
                        <CardHeader>
                            <CardTitle className="text-lg flex items-center gap-2">
                                <MapPin className="h-5 w-5 text-coreops-primary" />
                                1. Seleccionar Servicio
                            </CardTitle>
                            <CardDescription>Escoge el servicio al que deseas enviar personal</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <Select value={selectedServiceId} onValueChange={setSelectedServiceId}>
                                <SelectTrigger className="w-full">
                                    <SelectValue placeholder="Elige un servicio..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {activeServices.length === 0 && <SelectItem value="none" disabled>No hay servicios activos</SelectItem>}
                                    {activeServices.map(s => (
                                        <SelectItem key={s.id} value={s.id}>
                                            {s.clientes?.razon_social} - {s.nombre}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>

                            {selectedService && (
                                <div className="mt-4 p-3 bg-muted/50 rounded-lg text-sm">
                                    <p className="font-semibold">{selectedService.clientes?.razon_social}</p>
                                    <p className="text-muted-foreground break-words">{selectedService.direccion}</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm">
                        <CardHeader>
                            <CardTitle className="text-lg flex items-center gap-2">
                                <User className="h-5 w-5 text-blue-500" />
                                2. Elegir Funcionario
                            </CardTitle>
                            <CardDescription>Identifica desde dónde parte el empleado</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <Select value={selectedFuncionarioId} onValueChange={setSelectedFuncionarioId}>
                                <SelectTrigger className="w-full">
                                    <SelectValue placeholder="Elige un funcionario..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {activeFuncionarios.length === 0 && <SelectItem value="none" disabled>No hay funcionarios activos</SelectItem>}
                                    {activeFuncionarios.map(f => (
                                        <SelectItem key={f.id} value={f.id}>
                                            {f.profiles?.nombre} {f.profiles?.apellido} - {f.cargo}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>

                            {selectedFuncionario && (
                                <div className="mt-4 p-3 bg-muted/50 rounded-lg text-sm">
                                    <p className="font-semibold">{selectedFuncionario.profiles?.nombre} {selectedFuncionario.profiles?.apellido}</p>
                                    <p className="text-muted-foreground break-words">{selectedFuncionario.direccion}</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    <Button
                        className="w-full h-12 text-md shadow-lg"
                        disabled={!selectedService || !selectedFuncionario}
                        onClick={handleGenerateRoute}
                    >
                        Generar Mapeo
                    </Button>
                </div>

                {/* Right Panel - Map Display */}
                <div className="lg:col-span-2">
                    <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm h-[600px] flex flex-col">
                        <CardContent className="p-2 flex-grow relative overflow-hidden h-full rounded-b-lg">
                            {!isLoaded ? (
                                <div className="h-full w-full flex flex-col items-center justify-center text-muted-foreground p-12 text-center bg-slate-50 dark:bg-slate-900/50 rounded-lg">
                                    {loadError ? (
                                        <>
                                            <Map className="h-16 w-16 mb-4 text-red-500 opacity-50" />
                                            <h3 className="text-xl font-semibold mb-2">Error de Google Maps</h3>
                                            <p className="max-w-sm">No se pudo cargar la API Key. Configura <code>VITE_GOOGLE_MAPS_API_KEY</code> en tu Vercel / .env</p>
                                        </>
                                    ) : (
                                        <>
                                            <Loader2 className="h-16 w-16 mb-4 opacity-50 animate-spin" />
                                            <h3 className="text-xl font-semibold mb-2">Cargando Mapas...</h3>
                                        </>
                                    )}
                                </div>
                            ) : directionsResponse ? (
                                <div className="h-full w-full relative">
                                    <GoogleMap
                                        center={MVD_CENTER}
                                        zoom={12}
                                        mapContainerStyle={{ width: '100%', height: '100%', borderRadius: '0.5rem' }}
                                        options={{
                                            zoomControl: true,
                                            streetViewControl: false,
                                            mapTypeControl: false,
                                            fullscreenControl: true,
                                        }}
                                    >
                                        <DirectionsRenderer
                                            directions={directionsResponse}
                                            options={{
                                                polylineOptions: { strokeColor: '#10b981', strokeWeight: 5 }
                                            }}
                                        />
                                        {serviceMarkers.map(m => (
                                            <Marker 
                                                key={m.id} 
                                                position={{lat: m.lat, lng: m.lng}} 
                                                title={m.title}
                                                icon="http://maps.google.com/mapfiles/ms/icons/green-dot.png" 
                                            />
                                        ))}
                                    </GoogleMap>

                                    {/* Overlay Helper */}
                                    <div className="absolute top-4 right-4 bg-white/95 dark:bg-slate-900/95 p-4 rounded-xl shadow-2xl border border-slate-200 dark:border-slate-700 w-72 backdrop-blur-md animate-in fade-in slide-in-from-right-4">
                                        <h4 className="font-bold flex items-center gap-2 text-slate-900 dark:text-white mb-2">
                                            <Navigation className="h-4 w-4 text-emerald-500" />
                                            Información de Ruta
                                        </h4>
                                        <div className="space-y-2 mb-4">
                                            <p className="text-sm font-semibold flex justify-between">
                                                <span className="text-slate-500">Distancia:</span> 
                                                <span>{distance}</span>
                                            </p>
                                            <p className="text-sm font-semibold flex justify-between">
                                                <span className="text-slate-500">Tiempo estimado:</span> 
                                                <span className="text-emerald-600 dark:text-emerald-400">{duration}</span>
                                            </p>
                                        </div>
                                        <div className="flex gap-2 mt-3">
                                            <Button
                                                size="sm"
                                                variant={directionsMode === 'TRANSIT' ? 'default' : 'outline'}
                                                onClick={() => { setDirectionsMode('TRANSIT'); handleGenerateRoute(); }}
                                                className={`flex-1 ${directionsMode === 'TRANSIT' ? 'bg-emerald-600 hover:bg-emerald-700 text-white' : ''}`}
                                            >
                                                Ómnibus
                                            </Button>
                                            <Button
                                                size="sm"
                                                variant={directionsMode === 'DRIVING' ? 'default' : 'outline'}
                                                onClick={() => { setDirectionsMode('DRIVING'); handleGenerateRoute(); }}
                                                className={`flex-1 ${directionsMode === 'DRIVING' ? 'bg-coreops-primary text-white' : ''}`}
                                            >
                                                Auto
                                            </Button>
                                        </div>
                                        <Button
                                            size="sm"
                                            variant="secondary"
                                            onClick={handleOpenExternalRoute}
                                            className="w-full mt-3 font-semibold"
                                        >
                                            Comparar todos los Ómnibus
                                        </Button>
                                    </div>
                                </div>
                            ) : (
                                <div className="h-full w-full flex flex-col items-center justify-center text-muted-foreground p-12 text-center bg-slate-50 dark:bg-slate-900/50 rounded-lg">
                                    <GoogleMap
                                        center={MVD_CENTER}
                                        zoom={12}
                                        mapContainerStyle={{ width: '100%', height: '100%', position: 'absolute', top: 0, left: 0, zIndex: 0 }}
                                        options={{ disableDefaultUI: true }}
                                    >
                                        {serviceMarkers.map(m => (
                                            <Marker 
                                                key={m.id} 
                                                position={{lat: m.lat, lng: m.lng}} 
                                                title={m.title}
                                                icon="http://maps.google.com/mapfiles/ms/icons/green-dot.png" 
                                            />
                                        ))}
                                    </GoogleMap>
                                    <div className="z-10 bg-white/90 dark:bg-slate-900/90 p-6 rounded-2xl shadow-xl backdrop-blur-md">
                                        <Map className="h-16 w-16 mb-4 opacity-40 mx-auto" />
                                        <h3 className="text-xl font-semibold mb-2">Visualizador Operativo</h3>
                                        <p className="max-w-sm text-sm">
                                            Selecciona un servicio y el funcionario designado en el panel lateral para calcular la mejor ruta.
                                        </p>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

import { useState, useMemo } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { FileText, Download, Calendar, ArrowRightCircle, Filter } from 'lucide-react';
import { useAsistencia } from '@/hooks/useAsistencia';
import { toast } from 'sonner';
import * as XLSX from 'xlsx';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';

export default function Reports() {
    const [desde, setDesde] = useState<string>(new Date().toISOString().substring(0, 8) + '01');
    const [hasta, setHasta] = useState<string>(new Date().toISOString().substring(0, 10));
    const [loadingReport, setLoadingReport] = useState(false);
    const [filtroFuncionario, setFiltroFuncionario] = useState<string>('todos');
    const [filtroServicio, setFiltroServicio] = useState<string>('todos');

    // Pass date filters to avoid massive overfetching
    const { getAsistencias } = useAsistencia(desde, hasta);
    const { data: asistencias = [], isLoading } = getAsistencias;

    // Obtener listas únicas con map y useMemo para evitar loops O(N^2) que congelan la UI
    const uniqueEmpleados = useMemo(() => {
        const map = new Map();
        asistencias.forEach((current: any) => {
            if (current.funcionario_id && !map.has(current.funcionario_id)) {
                map.set(current.funcionario_id, current);
            }
        });
        return Array.from(map.values()).sort((a: any, b: any) => {
            const nameA = a.funcionarios?.profiles?.nombre || '';
            const nameB = b.funcionarios?.profiles?.nombre || '';
            return nameA.localeCompare(nameB);
        });
    }, [asistencias]);

    const uniqueServicios = useMemo(() => {
        const map = new Map();
        asistencias.forEach((current: any) => {
            const servicioId = current.horarios?.servicio_id;
            if (servicioId && !map.has(servicioId)) {
                map.set(servicioId, current);
            }
        });
        return Array.from(map.values()).sort((a: any, b: any) => {
            const nameA = a.horarios?.servicios?.nombre || '';
            const nameB = b.horarios?.servicios?.nombre || '';
            return nameA.localeCompare(nameB);
        });
    }, [asistencias]);

    const generarReporteCSV = (tipo: 'empleados' | 'clientes' | 'quincena1') => {
        setLoadingReport(true);
        toast.info(`Generando reporte de ${tipo}...`);

        setTimeout(() => {
            // Filtrar asistencias por rango de fechas
            const registrosRango = asistencias.filter((a: any) => {
                 return a.fecha >= desde && a.fecha <= hasta;
            });

            let registrosAUsar = registrosRango;

            // Aplicar filtros adicionales si están seleccionados
            if (filtroFuncionario !== 'todos') {
                registrosAUsar = registrosAUsar.filter((a: any) => a.funcionario_id === filtroFuncionario);
            }
            if (filtroServicio !== 'todos') {
                registrosAUsar = registrosAUsar.filter((a: any) => a.horarios?.servicio_id === filtroServicio);
            }

            if (tipo === 'quincena1') {
                registrosAUsar = registrosAUsar.filter(a => parseInt(a.fecha.split('-')[2]) <= 15);
            }

            if (registrosAUsar.length === 0) {
                toast.error('No hay datos registrados en el período seleccionado para exportar.');
                setLoadingReport(false);
                return;
            }

            // Agrupar datos según el tipo
            let dataToExport: any[] = [];
            if (tipo === 'empleados' || tipo === 'quincena1') {
                // Ordenar por empleado alfabéticamente, y luego por fecha
                const registrosOrdenados = [...registrosAUsar].sort((a, b) => {
                    const nameA = a.funcionarios?.profiles?.nombre || '';
                    const nameB = b.funcionarios?.profiles?.nombre || '';
                    if (nameA !== nameB) return nameA.localeCompare(nameB);
                    return a.fecha.localeCompare(b.fecha);
                });

                dataToExport = registrosOrdenados.map(r => {
                    let totalHoras = '0 hs';
                    const hEntrada = r.horarios?.hora_entrada?.substring(0, 5);
                    const hSalida = r.horarios?.hora_salida?.substring(0, 5);

                    if (hEntrada && hSalida) {
                        const [eH, eM] = hEntrada.split(':').map(Number);
                        const [sH, sM] = hSalida.split(':').map(Number);
                        let minutes = (sH * 60 + sM) - (eH * 60 + eM);
                        if (minutes < 0) minutes += 24 * 60; // manejo de turnos de noche

                        const hours = Math.floor(minutes / 60);
                        const mins = minutes % 60;
                        totalHoras = mins === 0 ? `${hours} hs` : `${hours}:${mins.toString().padStart(2, '0')} hs`;
                    }

                    return {
                        'Nombre Empleado': `${r.funcionarios?.profiles?.nombre} ${r.funcionarios?.profiles?.apellido}`,
                        'Fecha': r.fecha,
                        'Cédula': r.funcionarios?.cedula || 'N/A',
                        'Cliente / Servicio': `${r.horarios?.servicios?.clientes?.razon_social || ''} - ${r.horarios?.servicios?.nombre || ''}`,
                        'Horario de Entrada': hEntrada || 'N/A',
                        'Horario de Salida': hSalida || 'N/A',
                        'Total Horas': totalHoras,
                        'Estado Confirmación': r.estado.toUpperCase(),
                        'Observaciones': r.observaciones || ''
                    };
                });
            } else if (tipo === 'clientes') {
                // Ordenar por Cliente, luego por Servicio, y luego por Fecha
                const registrosOrdenados = [...registrosAUsar].sort((a, b) => {
                    const clientA = a.horarios?.servicios?.clientes?.razon_social || '';
                    const clientB = b.horarios?.servicios?.clientes?.razon_social || '';
                    if (clientA !== clientB) return clientA.localeCompare(clientB);

                    const servA = a.horarios?.servicios?.nombre || '';
                    const servB = b.horarios?.servicios?.nombre || '';
                    if (servA !== servB) return servA.localeCompare(servB);

                    return a.fecha.localeCompare(b.fecha);
                });

                dataToExport = registrosOrdenados.map(r => {
                    let totalHoras = '0 hs';
                    const hEntrada = r.horarios?.hora_entrada?.substring(0, 5);
                    const hSalida = r.horarios?.hora_salida?.substring(0, 5);

                    if (hEntrada && hSalida) {
                        const [eH, eM] = hEntrada.split(':').map(Number);
                        const [sH, sM] = hSalida.split(':').map(Number);
                        let minutes = (sH * 60 + sM) - (eH * 60 + eM);
                        if (minutes < 0) minutes += 24 * 60; // manejo de turnos de noche

                        const hours = Math.floor(minutes / 60);
                        const mins = minutes % 60;
                        totalHoras = mins === 0 ? `${hours} hs` : `${hours}:${mins.toString().padStart(2, '0')} hs`;
                    }

                    return {
                        'Cliente': r.horarios?.servicios?.clientes?.razon_social || 'N/A',
                        'Servicio': r.horarios?.servicios?.nombre || 'N/A',
                        'Fecha': r.fecha,
                        'Nombre Empleado': `${r.funcionarios?.profiles?.nombre} ${r.funcionarios?.profiles?.apellido}`,
                        'Horario de Entrada': hEntrada || 'N/A',
                        'Horario de Salida': hSalida || 'N/A',
                        'Total Horas': totalHoras,
                        'Estado': r.estado.toUpperCase(),
                        'Observaciones': r.observaciones || ''
                    };
                });
            }

            // Calcular el total global de tiempo en todos los registros mostrados
            let totalMinutosGlobal = 0;
            dataToExport.forEach(row => {
                if (row['Total Horas'] && row['Total Horas'] !== '0 hs') {
                    const timePart = row['Total Horas'].replace(' hs', '').trim();
                    const parts = timePart.split(':');
                    if (parts.length === 2) {
                        totalMinutosGlobal += (parseInt(parts[0]) * 60) + parseInt(parts[1]);
                    } else if (parts.length === 1) {
                        totalMinutosGlobal += parseInt(parts[0]) * 60;
                    }
                }
            });

            if (totalMinutosGlobal > 0) {
                const totalHoursCalculated = Math.floor(totalMinutosGlobal / 60);
                const totalMinsCalculated = totalMinutosGlobal % 60;
                const formattedGlobalTotal = totalMinsCalculated === 0
                    ? `${totalHoursCalculated} hs`
                    : `${totalHoursCalculated}:${totalMinsCalculated.toString().padStart(2, '0')} hs`;

                // Agregar una fila en blanco separadora
                dataToExport.push({});

                // Crear objeto de total. Mapear "Total Horas" a la columna respectiva, 
                // y usar la primera columna disponible para el texto "TOTAL GLOBAL DE HORAS DE ESTE REPORTE"
                const summaryRow: any = {};
                const firstKey = Object.keys(dataToExport[0])[0]; // 'Nombre Empleado' o 'Cliente'
                summaryRow[firstKey] = '=> TOTAL GLOBAL DE HORAS DE ESTE REPORTE <=';
                summaryRow['Total Horas'] = formattedGlobalTotal;

                // Si el reporte es 'empleados', 'Total Horas' se llamaba diferente. Lo unificamos.
                if (tipo !== 'clientes') {
                    summaryRow['Total Horas Teóricas'] = formattedGlobalTotal;
                    delete summaryRow['Total Horas'];
                }

                dataToExport.push(summaryRow);
            }

            // Generar y descargar archivo Excel
            const worksheet = XLSX.utils.json_to_sheet(dataToExport);
            const workbook = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(workbook, worksheet, "Reporte");
            XLSX.writeFile(workbook, `reporte_soclean_${tipo}_${desde}_al_${hasta}.xlsx`);

            toast.success('Reporte exportado exitosamente con ruta de auditoría adjunta');
            setLoadingReport(false);
        }, 1200);
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-primary flex items-center gap-2">
                        <FileText className="h-8 w-8 text-coreops-primary" />
                        Reportes Gerenciales y de Operaciones
                    </h2>
                    <p className="text-muted-foreground text-sm mt-1">Generación de archivos para Recursos Humanos, Administración y Alta Dirección.</p>
                </div>
            </div>

            <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 shadow-sm">
                <CardHeader className="border-b bg-slate-50 dark:bg-slate-900/50">
                    <CardTitle className="text-lg flex items-center gap-2">
                        <Calendar className="h-5 w-5 text-slate-500" />
                        Selección de Período a Exportar
                    </CardTitle>
                </CardHeader>
                <CardContent className="pt-6">
                    <div className="flex flex-col md:flex-row gap-4 mb-8">
                        <div className="w-full md:w-48 space-y-2">
                            <label className="text-sm font-semibold text-slate-700">Fecha Desde</label>
                            <input
                                type="date"
                                value={desde}
                                onChange={(e) => setDesde(e.target.value)}
                                className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-coreops-primary"
                            />
                        </div>
                        <div className="w-full md:w-48 space-y-2">
                            <label className="text-sm font-semibold text-slate-700">Fecha Hasta</label>
                            <input
                                type="date"
                                value={hasta}
                                onChange={(e) => setHasta(e.target.value)}
                                className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-coreops-primary"
                            />
                        </div>

                        <div className="w-full md:w-64 space-y-2">
                            <label className="text-sm font-semibold text-slate-700 flex items-center gap-1">
                                <Filter className="h-3 w-3" />
                                Filtrar por Funcionario
                            </label>
                            <Select value={filtroFuncionario} onValueChange={setFiltroFuncionario}>
                                <SelectTrigger className="h-10 border-slate-300">
                                    <SelectValue placeholder="Todos los funcionarios" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="todos">Todos los Empleados</SelectItem>
                                    {uniqueEmpleados.map((a: any) => (
                                        <SelectItem key={`emp_${a.funcionario_id}`} value={a.funcionario_id}>
                                            {a.funcionarios?.profiles?.nombre} {a.funcionarios?.profiles?.apellido}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>

                        <div className="w-full md:w-72 space-y-2">
                            <label className="text-sm font-semibold text-slate-700 flex items-center gap-1">
                                <Filter className="h-3 w-3" />
                                Filtrar por Servicio
                            </label>
                            <Select value={filtroServicio} onValueChange={setFiltroServicio}>
                                <SelectTrigger className="h-10 border-slate-300">
                                    <SelectValue placeholder="Todos los servicios" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="todos">Todos los Servicios</SelectItem>
                                    {uniqueServicios.map((a: any) => (
                                        <SelectItem key={`srv_${a.horarios?.servicio_id}`} value={a.horarios?.servicio_id}>
                                            {a.horarios?.servicios?.clientes?.razon_social} - {a.horarios?.servicios?.nombre}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

                        {/* Reporte RRHH (1) */}
                        <div className="p-5 border border-slate-200 dark:border-slate-800 rounded-xl bg-white hover:border-coreops-primary transition-colors flex flex-col h-full shadow-sm">
                            <h3 className="font-bold text-lg mb-2 text-slate-800">Cierre 1ra Quincena (RRHH)</h3>
                            <p className="text-sm text-slate-500 mb-6 flex-grow">Archivo detallado de la primer quincena para adelantos de nómina. Para enviar el día 16 de cada mes.</p>
                            <Button
                                className="w-full bg-slate-800 hover:bg-slate-700"
                                onClick={() => generarReporteCSV('quincena1')}
                                disabled={loadingReport || isLoading}
                            >
                                <Download className="h-4 w-4 mr-2" />
                                Exportar Quincena a Excel
                            </Button>
                        </div>

                        {/* Reporte RRHH (2) */}
                        <div className="p-5 border border-slate-200 dark:border-slate-800 rounded-xl bg-white hover:border-coreops-primary transition-colors flex flex-col h-full shadow-sm">
                            <h3 className="font-bold text-lg mb-2 text-slate-800">Nómina Mensual Empleados</h3>
                            <p className="text-sm text-slate-500 mb-6 flex-grow">Horas reales trabajadas día por día por cada empleado. Para enviar el día 1 de cada mes al departamento de liquidación.</p>
                            <Button
                                className="w-full bg-coreops-primary hover:bg-coreops-secondary"
                                onClick={() => generarReporteCSV('empleados')}
                                disabled={loadingReport || isLoading}
                            >
                                <Download className="h-4 w-4 mr-2" />
                                Exportar Mes a Excel
                            </Button>
                        </div>

                        {/* Reporte Administración (3) */}
                        <div className="p-5 border border-slate-200 dark:border-slate-800 rounded-xl bg-blue-50/50 hover:border-blue-300 transition-colors flex flex-col h-full shadow-sm">
                            <h3 className="font-bold text-lg mb-2 text-blue-900">Control Servicios a Clientes</h3>
                            <p className="text-sm text-slate-600 mb-6 flex-grow">Reporte de horas trabajadas y servicios caídos diferenciado por cliente. Ideal para el departamento de Facturación (día 1).</p>
                            <Button
                                variant="outline"
                                className="w-full border-blue-500 text-blue-700 hover:bg-blue-50"
                                onClick={() => generarReporteCSV('clientes')}
                                disabled={loadingReport || isLoading}
                            >
                                <ArrowRightCircle className="h-4 w-4 mr-2" />
                                Exportar a Administración
                            </Button>
                        </div>

                    </div>
                </CardContent>
            </Card>

            <div className="bg-slate-100 p-4 border border-slate-200 text-sm text-slate-500 rounded-xl flex items-start gap-4">
                <div className="p-2 bg-white rounded-lg inline-flex">
                    <FileText className="h-5 w-5 text-slate-400" />
                </div>
                <div>
                    <strong className="block text-slate-700 mb-1">Registro de Auditoría Interna Activo</strong>
                    Todos los reportes incluyen digitalmente los logs inmutables que registran quién (usuario), a qué hora,
                    y qué registros editó a lo largo del mes en el sistema operativo central garantizando 100% de trazabilidad para la Dirección y Jefatura.
                </div>
            </div>
        </div>
    );
}

import { useState, useMemo } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { PlusCircle, Pencil, Search, CalendarClock, Trash2, Smartphone, Printer, Calendar, ListFilter } from 'lucide-react';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Input } from '@/components/ui/input';
import { HorarioFormDialog } from '@/components/horarios/HorarioFormDialog';
import { HorarioPrintDialog } from '@/components/horarios/HorarioPrintDialog';
import { useHorarios } from '@/hooks/useHorarios';
import { useCertificaciones } from '@/hooks/useCertificaciones';
import type { Horario } from '@/types';
import { toast } from 'sonner';

const DIAS_MAP: Record<number, string> = {
    0: 'Domingo',
    1: 'Lunes',
    2: 'Martes',
    3: 'Miércoles',
    4: 'Jueves',
    5: 'Viernes',
    6: 'Sábado'
};

// Default to tomorrow's date
function getTomorrowStr(): string {
    const d = new Date();
    d.setDate(d.getDate() + 1);
    return d.toISOString().split('T')[0]; // YYYY-MM-DD
}

const dateFormatter = new Intl.DateTimeFormat('es-UY');

export default function Schedules() {
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [isPrintDialogOpen, setIsPrintDialogOpen] = useState(false);
    const [editingHorario, setEditingHorario] = useState<Horario | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [fechaFiltro, setFechaFiltro] = useState<string>(getTomorrowStr());
    const [showAll, setShowAll] = useState(false);

    const { getHorarios, deleteHorario } = useHorarios();
    const { data: horarios = [], isLoading: isLoadingHorarios } = getHorarios;

    const { getAllCertificaciones } = useCertificaciones();
    const { data: certificaciones = [] } = getAllCertificaciones;

    const isLoading = isLoadingHorarios;

    // Get day of week from selected date (0=Sun ... 6=Sat)
    const diaSemanaFiltro = useMemo(() => {
        if (showAll || !fechaFiltro) return null;
        const d = new Date(fechaFiltro + 'T12:00:00');
        return d.getDay();
    }, [fechaFiltro, showAll]);

    const fechaLabel = useMemo(() => {
        if (!fechaFiltro) return '';
        const d = new Date(fechaFiltro + 'T12:00:00');
        return d.toLocaleDateString('es-UY', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
    }, [fechaFiltro]);

    const handleEdit = (horario: Horario) => {
        setEditingHorario(horario);
        setIsDialogOpen(true);
    };

    const handeAddNew = () => {
        setEditingHorario(null);
        setIsDialogOpen(true);
    };

    const handleDelete = async (id: string) => {
        if (confirm('¿Estás seguro de que deseas eliminar este horario asignado?')) {
            try {
                await deleteHorario.mutateAsync(id);
                toast.success('Horario eliminado');
            } catch (error: any) {
                toast.error(error.message || 'Error al eliminar');
            }
        }
    };

    const filteredHorarios = horarios.filter((h: Horario) => {
        // Filter by day of week if a date is selected
        if (diaSemanaFiltro !== null && h.dia_semana !== diaSemanaFiltro) return false;

        // Filter by vigencia: must be active on the selected date
        if (!showAll && fechaFiltro) {
            if (h.vigente_desde && fechaFiltro < h.vigente_desde) return false;
            if (h.vigente_hasta && fechaFiltro > h.vigente_hasta) return false;
        }

        const search = searchTerm.toLowerCase();
        const func = h.funcionarios?.profiles?.nombre?.toLowerCase() + ' ' + h.funcionarios?.profiles?.apellido?.toLowerCase();
        const serv = h.servicios?.clientes?.razon_social?.toLowerCase() + ' ' + h.servicios?.nombre?.toLowerCase();
        return func.includes(search) || serv.includes(search);
    });

    const openWhatsApp = (h: Horario) => {
        const nombreFuncionario = `${h.funcionarios?.profiles?.nombre} ${h.funcionarios?.profiles?.apellido}`;
        const cliente = h.servicios?.clientes?.razon_social || '';
        const direccion = h.servicios?.direccion || '';
        const dia = DIAS_MAP[h.dia_semana] || '';
        const entrada = h.hora_entrada.substring(0, 5);
        const salida = h.hora_salida.substring(0, 5);

        const text = `Hola *${nombreFuncionario}*, te informamos de tu coordinación de servicio:\n\n*📌 Cliente:* ${cliente}\n*📍 Ubicación:* ${direccion}\n*🗓 Día:* ${dia}\n*⌚ Horario:* ${entrada} hs a ${salida} hs\n\nPor favor, confirmá la recepción de este mensaje. ¡Gracias!`;

        const encodedText = encodeURIComponent(text);
        const whatsappUrl = `https://api.whatsapp.com/send?text=${encodedText}`;
        window.open(whatsappUrl, '_blank');
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-primary flex items-center gap-2">
                        <CalendarClock className="h-8 w-8" />
                        Horarios y Turnos
                    </h2>
                    <p className="text-muted-foreground text-sm mt-1">Programa qué días de la semana un empleado cubre el servicio de cierto cliente.</p>
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                    <Button onClick={handeAddNew} className="bg-primary group hover:bg-primary/90 text-white rounded-xl shadow-lg hover:shadow-xl transition-all h-11 shrink-0">
                        <PlusCircle className="mr-2 h-5 w-5 group-hover:rotate-90 transition-transform" />
                        Asignar Horario
                    </Button>
                </div>
            </div>

            <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm">
                <CardHeader className="pb-4 space-y-4">
                    <div className="flex flex-col sm:flex-row justify-between w-full items-center gap-4">
                        <CardTitle className="text-lg flex-1">Cronograma de Asignaciones</CardTitle>
                        <div className="relative w-full sm:w-72">
                            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Buscar por empleado o cliente..."
                                className="pl-9 bg-background/50 border-slate-200 dark:border-slate-700"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <Button
                            variant="outline"
                            onClick={() => setIsPrintDialogOpen(true)}
                            disabled={filteredHorarios.length === 0}
                            className="shrink-0"
                        >
                            <Printer className="h-4 w-4 mr-2" /> Imprimir
                        </Button>
                    </div>

                    {/* Date filter row */}
                    <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 pt-2 border-t border-slate-100 dark:border-slate-800">
                        <div className="flex items-center gap-2">
                            <Calendar className="h-4 w-4 text-coreops-primary" />
                            <span className="text-sm font-semibold text-slate-700 dark:text-slate-300">Filtrar por fecha:</span>
                        </div>
                        <input
                            type="date"
                            value={fechaFiltro}
                            onChange={(e) => { setFechaFiltro(e.target.value); setShowAll(false); }}
                            className="flex h-9 rounded-md border border-slate-300 bg-white px-3 py-1 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-coreops-primary dark:bg-slate-800 dark:text-white dark:border-slate-600"
                        />
                        <Button
                            variant={showAll ? 'default' : 'outline'}
                            size="sm"
                            onClick={() => setShowAll(!showAll)}
                            className={showAll ? 'bg-coreops-primary hover:bg-coreops-secondary text-white' : ''}
                        >
                            <ListFilter className="h-4 w-4 mr-1" />
                            {showAll ? 'Mostrando Todos' : 'Ver Todos'}
                        </Button>
                        {!showAll && fechaFiltro && (
                            <span className="text-sm text-muted-foreground capitalize">
                                📅 Mostrando horarios del <strong>{fechaLabel}</strong> ({filteredHorarios.length} asignaciones)
                            </span>
                        )}
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="rounded-md border border-slate-200 dark:border-slate-800 bg-background/50 overflow-x-auto overflow-y-hidden">
                        <Table className="min-w-[800px]">
                            <TableHeader className="bg-muted/50">
                                <TableRow>
                                    <TableHead>Día y Franja</TableHead>
                                    <TableHead>Funcionario Asignado</TableHead>
                                    <TableHead>Cliente y Ubicación</TableHead>
                                    <TableHead>Vigencia</TableHead>
                                    <TableHead className="text-right">Acciones</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {isLoading ? (
                                    <TableRow>
                                        <TableCell colSpan={5} className="text-center h-24 text-muted-foreground">
                                            Cargando horarios de trabajo...
                                        </TableCell>
                                    </TableRow>
                                ) : filteredHorarios.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={5} className="text-center h-24 text-muted-foreground">
                                            Aún no hay horarios o turnos asigandos al personal.
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    filteredHorarios.map((h: Horario) => (
                                        <TableRow key={h.id} className="group hover:bg-muted/30 transition-colors">
                                            <TableCell>
                                                <div className="font-bold text-coreops-primary dark:text-blue-400">
                                                    {DIAS_MAP[h.dia_semana]}
                                                </div>
                                                <div className="text-sm font-mono text-slate-600 dark:text-slate-300">
                                                    {h.hora_entrada.substring(0, 5)} - {h.hora_salida.substring(0, 5)}
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="font-medium text-slate-800 dark:text-slate-200">
                                                    {h.funcionarios?.profiles?.nombre} {h.funcionarios?.profiles?.apellido}
                                                </div>
                                                <div className="text-xs text-muted-foreground line-clamp-1">{h.funcionarios?.cargo}</div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="font-semibold">{h.servicios?.clientes?.razon_social}</div>
                                                <div className="text-xs text-muted-foreground">
                                                    {h.servicios?.nombre} | {h.servicios?.direccion}
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="text-xs text-muted-foreground">
                                                    Desde: {dateFormatter.format(new Date(h.vigente_desde))}
                                                    {h.vigente_hasta ? <><br />Hasta: {dateFormatter.format(new Date(h.vigente_hasta))}</> : ''}
                                                </div>
                                                {!h.vigente_hasta && <span className="block mt-1 text-xs text-emerald-600 dark:text-emerald-400 font-medium">Activo Indefinido</span>}
                                                
                                                {/* Check Certificación */}
                                                {!showAll && fechaFiltro && (
                                                    (() => {
                                                        const isCertificated = certificaciones.some(c => 
                                                            c.funcionario_id === h.funcionario_id && 
                                                            fechaFiltro >= c.fecha_inicio && 
                                                            fechaFiltro <= c.fecha_fin
                                                        );
                                                        return isCertificated ? (
                                                            <div className="mt-1.5 inline-flex items-center gap-1 bg-cyan-100 dark:bg-cyan-900/30 text-cyan-800 dark:text-cyan-400 px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider border border-cyan-200 dark:border-cyan-800">
                                                                Certificado Médico
                                                            </div>
                                                        ) : null;
                                                    })()
                                                )}
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        onClick={() => openWhatsApp(h)}
                                                        className="text-emerald-600 hover:text-emerald-700 hover:bg-emerald-50"
                                                        title="Enviar por WhatsApp"
                                                    >
                                                        <Smartphone className="h-4 w-4" />
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        onClick={() => handleEdit(h)}
                                                        className="text-muted-foreground hover:text-primary"
                                                        title="Editar"
                                                    >
                                                        <Pencil className="h-4 w-4" />
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        onClick={() => handleDelete(h.id)}
                                                        className="text-muted-foreground hover:text-red-500"
                                                        title="Eliminar"
                                                    >
                                                        <Trash2 className="h-4 w-4" />
                                                    </Button>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))
                                )}
                            </TableBody>
                        </Table>
                    </div>
                </CardContent>
            </Card>

            <HorarioFormDialog
                open={isDialogOpen}
                onOpenChange={setIsDialogOpen}
                horarioToEdit={editingHorario}
            />

            <HorarioPrintDialog
                open={isPrintDialogOpen}
                onOpenChange={setIsPrintDialogOpen}
                horarios={filteredHorarios}
            />
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useTheme } from '@/components/theme-provider';
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { User, Shield, Bell, Key, Store, Moon, Sun, Database, Download } from 'lucide-react';
import * as XLSX from 'xlsx';
import { format } from 'date-fns';
import { useAuthStore } from '@/stores/authStore';
import { supabase } from '@/lib/supabase';
import { toast } from 'sonner';

export default function Settings() {
    const { user, role } = useAuthStore();
    const { theme, setTheme } = useTheme();
    
    const [isSaving, setIsSaving] = useState(false);
    const [isSavingEmpresa, setIsSavingEmpresa] = useState(false);

    const [activeTab, setActiveTab] = useState('perfil');
    const [notifications, setNotifications] = useState(() => localStorage.getItem('soclean-notifications') !== 'false');

    // Empresa form state
    const [empresaId, setEmpresaId] = useState<string | null>(null);
    const [razonSocial, setRazonSocial] = useState('');
    const [rut, setRut] = useState('');
    const [direccion, setDireccion] = useState('');
    const [telefono, setTelefono] = useState('');

    // Profile form state
    const [nombre, setNombre] = useState('');
    const [apellido, setApellido] = useState('');

    // Password form state
    const [newPass, setNewPass] = useState('');
    const [confirmPass, setConfirmPass] = useState('');
    const [isChangingPass, setIsChangingPass] = useState(false);

    // Load current profile and empresa config from Supabase
    useEffect(() => {
        async function loadData() {
            if (!user) return;
            
            // Load Profile
            const { data: profile } = await supabase
                .from('profiles')
                .select('nombre, apellido')
                .eq('id', user.id)
                .single();

            if (profile) {
                setNombre(profile.nombre || '');
                setApellido(profile.apellido || '');
            }

            // Load Empresa Config
            const { data: empresa } = await supabase
                .from('empresa_config')
                .select('*')
                .limit(1)
                .maybeSingle();
                
            if (empresa) {
                setEmpresaId(empresa.id);
                setRazonSocial(empresa.razon_social || '');
                setRut(empresa.rut || '');
                setDireccion(empresa.direccion || '');
                setTelefono(empresa.telefono || '');
            }
        }
        loadData();
    }, [user]);

    const handleSaveProfile = async () => {
        if (!user) return;
        setIsSaving(true);
        try {
            const { error } = await supabase
                .from('profiles')
                .update({ nombre, apellido })
                .eq('id', user.id);

            if (error) throw error;
            toast.success("Perfil actualizado correctamente en la base de datos.");
        } catch (err: any) {
            toast.error(err.message || "No se pudo guardar el perfil.");
        } finally {
            setIsSaving(false);
        }
    };

    const handleSaveEmpresa = async () => {
        if (role !== 'superadmin') {
            toast.error("Solo los superadministradores pueden modificar los datos de la empresa.");
            return;
        }
        setIsSavingEmpresa(true);
        try {
            const payload = {
                razon_social: razonSocial,
                rut,
                direccion,
                telefono,
                updated_at: new Date().toISOString()
            };

            let err;
            if (empresaId) {
                const { error } = await supabase.from('empresa_config').update(payload).eq('id', empresaId);
                err = error;
            } else {
                const { data, error } = await supabase.from('empresa_config').insert([payload]).select().single();
                if (data) setEmpresaId(data.id);
                err = error;
            }

            if (err) throw err;
            toast.success("Datos de la empresa actualizados exitosamente.");
        } catch (error: any) {
            toast.error(error.message || "Error al guardar los datos de la empresa.");
        } finally {
            setIsSavingEmpresa(false);
        }
    };

    const toggleNotifications = () => {
        const newVal = !notifications;
        setNotifications(newVal);
        localStorage.setItem('soclean-notifications', String(newVal));
        if (newVal) {
            toast.success("Notificaciones UI/UX activadas.");
        } else {
            toast.info("Notificaciones UI/UX desactivadas.");
        }
    };

    const [backups, setBackups] = useState<any[]>([]);
    const [isGeneratingBackup, setIsGeneratingBackup] = useState(false);

    const loadBackups = async () => {
        if (role !== 'superadmin') return;
        const { data } = await supabase.from('backups_log').select('*, profiles(nombre, apellido)').order('created_at', { ascending: false });
        if (data) setBackups(data);
    };

    useEffect(() => {
        if (activeTab === 'backups') {
            loadBackups();
        }
    }, [activeTab]);

    const handleGenerateBackup = async () => {
        if (role !== 'superadmin') return;
        setIsGeneratingBackup(true);
        try {
            toast.info("Recopilando datos para el respaldo...");
            
            const [asistencia, horarios, facturas, clientes, perfiles] = await Promise.all([
                supabase.from('asistencia').select('*'),
                supabase.from('horarios').select('*'),
                supabase.from('facturas').select('*'),
                supabase.from('clientes').select('*'),
                supabase.from('profiles').select('*')
            ]);
            
            const wb = XLSX.utils.book_new();
            
            const addSheet = (data: any, name: string) => {
                if (data && data.data && data.data.length > 0) {
                    const ws = XLSX.utils.json_to_sheet(data.data);
                    XLSX.utils.book_append_sheet(wb, ws, name);
                }
            };
            
            addSheet(asistencia, 'Asistencia');
            addSheet(horarios, 'Horarios');
            addSheet(facturas, 'Facturas');
            addSheet(clientes, 'Clientes');
            addSheet(perfiles, 'Usuarios');
            
            const excelBuffer = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });
            
            const timestamp = format(new Date(), 'yyyy-MM-dd_HH-mm-ss');
            const fileName = `backup_soclean_${timestamp}.xlsx`;
            
            const { data: uploadData, error: uploadError } = await supabase.storage
                .from('backups')
                .upload(fileName, excelBuffer, {
                    contentType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                    upsert: false
                });
                
            if (uploadError) throw uploadError;
            
            const savedPath = uploadData.path;
            
            const { error: logError } = await supabase.from('backups_log').insert([{
                tipo: 'MANUAL',
                estado: 'COMPLETADO',
                archivo_url: savedPath,
                realizado_por: user?.id
            }]);
            
            if (logError) throw logError;
            
            toast.success("Respaldo completado y guardado en la nube.");
            loadBackups();
        } catch (error: any) {
            console.error("Error generating backup:", error);
            toast.error("Error al generar el respaldo: " + error.message);
        } finally {
            setIsGeneratingBackup(false);
        }
    };
    
    const downloadBackup = async (path: string) => {
        try {
            toast.info("Descargando archivo...");
            const { data, error } = await supabase.storage.from('backups').download(path);
            if (error) throw error;
            
            const url = window.URL.createObjectURL(data);
            const a = document.createElement('a');
            a.href = url;
            a.download = path.split('/').pop() || 'backup.xlsx';
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            document.body.removeChild(a);
        } catch (error: any) {
            toast.error("No se pudo descargar el archivo: " + error.message);
        }
    };

    const handleChangePassword = async () => {
        if (!newPass || newPass.length < 6) {
            toast.error("La contraseña debe tener al menos 6 caracteres.");
            return;
        }
        if (newPass !== confirmPass) {
            toast.error("Las contraseñas no coinciden.");
            return;
        }

        setIsChangingPass(true);
        try {
            const { error } = await supabase.auth.updateUser({ password: newPass });
            if (error) throw error;
            toast.success("Contraseña actualizada exitosamente.");
            setNewPass('');
            setConfirmPass('');
        } catch (err: any) {
            toast.error(err.message || "No se pudo cambiar la contraseña.");
        } finally {
            setIsChangingPass(false);
        }
    };

    return (
        <div className="space-y-6 max-w-5xl mx-auto animate-in fade-in duration-500">
            <div className="flex flex-col gap-2">
                <h1 className="text-3xl font-bold tracking-tight text-primary flex items-center gap-2">
                    <Store className="h-8 w-8 text-coreops-primary" />
                    Configuración del Sistema
                </h1>
                <p className="text-muted-foreground">
                    Administra tus preferencias, ajustes de cuenta y reglas del negocio.
                </p>
            </div>

            <div className="flex flex-col md:flex-row gap-6 w-full mt-6">
                <div className="flex flex-col gap-2 w-full md:w-64 shrink-0 p-4 bg-slate-100 dark:bg-slate-800 rounded-xl">
                    <button onClick={() => setActiveTab('perfil')} className={`text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors ${activeTab === 'perfil' ? 'bg-white dark:bg-slate-900 shadow-sm font-semibold' : 'hover:bg-slate-200 dark:hover:bg-slate-700/50'}`}>
                        <User className="h-5 w-5" /> Mi Perfil
                    </button>
                    <button onClick={() => setActiveTab('empresa')} className={`text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors ${activeTab === 'empresa' ? 'bg-white dark:bg-slate-900 shadow-sm font-semibold' : 'hover:bg-slate-200 dark:hover:bg-slate-700/50'}`}>
                        <Store className="h-5 w-5" /> Datos de Empresa
                    </button>
                    <button onClick={() => setActiveTab('preferencias')} className={`text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors ${activeTab === 'preferencias' ? 'bg-white dark:bg-slate-900 shadow-sm font-semibold' : 'hover:bg-slate-200 dark:hover:bg-slate-700/50'}`}>
                        <Bell className="h-5 w-5" /> Preferencias
                    </button>
                    <button onClick={() => setActiveTab('seguridad')} className={`text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors ${activeTab === 'seguridad' ? 'bg-white dark:bg-slate-900 shadow-sm font-semibold' : 'hover:bg-slate-200 dark:hover:bg-slate-700/50'}`}>
                        <Shield className="h-5 w-5" /> Seguridad
                    </button>
                    {role === 'superadmin' && (
                        <button onClick={() => setActiveTab('backups')} className={`text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors ${activeTab === 'backups' ? 'bg-white dark:bg-slate-900 shadow-sm font-semibold' : 'hover:bg-slate-200 dark:hover:bg-slate-700/50'}`}>
                            <Database className="h-5 w-5" /> Backups en Nube
                        </button>
                    )}
                </div>

                <div className="flex-1">
                    {activeTab === 'perfil' && (
                        <Card className="border-slate-200 dark:border-slate-800 shadow-sm bg-white/60 dark:bg-slate-900/60 backdrop-blur-md">
                            <CardHeader>
                                <CardTitle>Información Personal</CardTitle>
                                <CardDescription>Actualiza tus datos de contacto y rol operativo.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="nombre">Nombre</Label>
                                        <Input id="nombre" value={nombre} onChange={(e) => setNombre(e.target.value)} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="apellido">Apellido</Label>
                                        <Input id="apellido" value={apellido} onChange={(e) => setApellido(e.target.value)} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="email">Correo Electrónico</Label>
                                        <Input id="email" defaultValue={user?.email || ''} disabled className="bg-slate-50 text-slate-500" />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="rol">Rol Asignado</Label>
                                        <Input id="rol" defaultValue={role?.toUpperCase() || ''} disabled className="bg-slate-50 text-slate-500 font-bold" />
                                    </div>
                                </div>
                            </CardContent>
                            <CardFooter className="border-t pt-6 bg-slate-50/50 dark:bg-slate-900/50">
                                <Button onClick={handleSaveProfile} disabled={isSaving} className="ml-auto bg-coreops-primary hover:bg-coreops-secondary">
                                    {isSaving ? 'Guardando...' : 'Guardar Cambios'}
                                </Button>
                            </CardFooter>
                        </Card>
                    )}

                    {activeTab === 'empresa' && (
                        <Card className="border-slate-200 dark:border-slate-800 shadow-sm bg-white/60 dark:bg-slate-900/60 backdrop-blur-md">
                            <CardHeader>
                                <CardTitle>Datos de la Empresa</CardTitle>
                                <CardDescription>Configuración global de Soclean que afecta a los reportes. Solo accesible por Superadmin.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="razon">Razón Social</Label>
                                        <Input id="razon" value={razonSocial} onChange={(e) => setRazonSocial(e.target.value)} disabled={role !== 'superadmin'} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="rut">RUT</Label>
                                        <Input id="rut" value={rut} onChange={(e) => setRut(e.target.value)} disabled={role !== 'superadmin'} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="direccion">Dirección Central</Label>
                                        <Input id="direccion" value={direccion} onChange={(e) => setDireccion(e.target.value)} disabled={role !== 'superadmin'} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="telefono">Teléfono Principal</Label>
                                        <Input id="telefono" value={telefono} onChange={(e) => setTelefono(e.target.value)} disabled={role !== 'superadmin'} />
                                    </div>
                                </div>
                            </CardContent>
                            <CardFooter className="border-t pt-6 bg-slate-50/50 dark:bg-slate-900/50">
                                <Button onClick={handleSaveEmpresa} disabled={isSavingEmpresa || role !== 'superadmin'} className="ml-auto bg-coreops-primary hover:bg-coreops-secondary">
                                    {isSavingEmpresa ? 'Guardando...' : 'Guardar Datos de Empresa'}
                                </Button>
                            </CardFooter>
                        </Card>
                    )}

                    {activeTab === 'preferencias' && (
                        <Card className="border-slate-200 dark:border-slate-800 shadow-sm bg-white/60 dark:bg-slate-900/60 backdrop-blur-md">
                            <CardHeader>
                                <CardTitle>Apariencia y Notificaciones</CardTitle>
                                <CardDescription>Personaliza tu experiencia dentro de la plataforma.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-6">
                                <div className="flex items-center justify-between border-b pb-4">
                                    <div>
                                        <h4 className="font-semibold text-slate-800 dark:text-slate-200">Tema Visual</h4>
                                        <p className="text-sm text-slate-500">Elige entre modo claro o oscuro.</p>
                                    </div>
                                    <div className="flex gap-2 bg-slate-100 p-1 rounded-lg dark:bg-slate-800">
                                        <Button variant={theme === 'light' ? 'default' : 'ghost'} size="sm" onClick={() => setTheme('light')} className={theme === 'light' ? 'bg-white text-slate-900 shadow-sm' : ''}>
                                            <Sun className="h-4 w-4 mr-2" /> Claro
                                        </Button>
                                        <Button variant={theme === 'dark' ? 'default' : 'ghost'} size="sm" onClick={() => setTheme('dark')} className={theme === 'dark' ? 'bg-slate-900 text-white shadow-sm' : ''}>
                                            <Moon className="h-4 w-4 mr-2" /> Oscuro
                                        </Button>
                                    </div>
                                </div>
                                <div className="flex items-center justify-between">
                                    <div>
                                        <h4 className="font-semibold text-slate-800 dark:text-slate-200">Notificaciones UI/UX</h4>
                                        <p className="text-sm text-slate-500">Mostrar alertas emergentes en pantalla.</p>
                                    </div>
                                    <Button variant={notifications ? 'default' : 'outline'} onClick={toggleNotifications} className={notifications ? 'bg-emerald-600 hover:bg-emerald-700' : ''}>
                                        {notifications ? 'Activadas' : 'Desactivadas'}
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {activeTab === 'seguridad' && (
                        <Card className="border-slate-200 dark:border-slate-800 shadow-sm bg-white/60 dark:bg-slate-900/60 backdrop-blur-md border border-red-100">
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2 text-red-600">
                                    <Key className="h-5 w-5" /> Cambiar Mi Contraseña
                                </CardTitle>
                                <CardDescription>Configura una nueva contraseña segura para tu cuenta.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="max-w-md space-y-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="new-pass">Nueva Contraseña</Label>
                                        <Input id="new-pass" type="password" value={newPass} onChange={(e) => setNewPass(e.target.value)} placeholder="Mínimo 6 caracteres" />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="confirm-pass">Confirmar Contraseña</Label>
                                        <Input id="confirm-pass" type="password" value={confirmPass} onChange={(e) => setConfirmPass(e.target.value)} placeholder="Repite la nueva contraseña" />
                                    </div>
                                </div>
                            </CardContent>
                            <CardFooter className="border-t pt-6 bg-red-50/30 dark:bg-red-900/10">
                                <Button variant="destructive" onClick={handleChangePassword} disabled={isChangingPass}>
                                    {isChangingPass ? 'Actualizando...' : 'Actualizar Credenciales'}
                                </Button>
                            </CardFooter>
                        </Card>
                    )}

                    {activeTab === 'backups' && role === 'superadmin' && (
                        <Card className="border-slate-200 dark:border-slate-800 shadow-sm bg-white/60 dark:bg-slate-900/60 backdrop-blur-md">
                            <CardHeader>
                                <CardTitle className="flex items-center justify-between">
                                    <span className="flex items-center gap-2">
                                        <Database className="h-6 w-6 text-coreops-primary" />
                                        Respaldos en la Nube (Supabase Storage)
                                    </span>
                                    <Button onClick={handleGenerateBackup} disabled={isGeneratingBackup} className="bg-coreops-primary hover:bg-coreops-secondary">
                                        {isGeneratingBackup ? 'Generando y Subiendo...' : 'Generar Backup Ahora'}
                                    </Button>
                                </CardTitle>
                                <CardDescription>Historial de respaldos extraídos y almacenados de forma segura en la nube. Los datos incluyen nómina, facturas, clientes, usuarios y horarios.</CardDescription>
                            </CardHeader>
                            <CardContent>
                                {backups.length === 0 ? (
                                    <div className="text-center py-8 text-slate-500">
                                        No hay respaldos registrados. Toca el botón para crear el primero.
                                    </div>
                                ) : (
                                    <div className="space-y-3">
                                        {backups.map((bk) => (
                                            <div key={bk.id} className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg border border-slate-100 dark:border-slate-800">
                                                <div>
                                                    <div className="font-semibold flex items-center gap-2">
                                                        {bk.tipo === 'MANUAL' ? 'Respaldo Manual' : 'Respaldo Automático'}
                                                        <span className={`text-xs px-2 py-0.5 rounded-full ${bk.estado === 'COMPLETADO' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                                                            {bk.estado}
                                                        </span>
                                                    </div>
                                                    <div className="text-sm text-slate-500 mt-1">
                                                        {format(new Date(bk.created_at), "dd 'de' MMMM, yyyy - HH:mm")} hs
                                                        {bk.profiles && ` • Por: ${bk.profiles.nombre} ${bk.profiles.apellido}`}
                                                    </div>
                                                </div>
                                                {bk.archivo_url && (
                                                    <Button variant="outline" size="sm" onClick={() => downloadBackup(bk.archivo_url)} className="flex gap-2">
                                                        <Download className="h-4 w-4" /> Descargar Excel
                                                    </Button>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useAsistencia } from '@/hooks/useAsistencia';
import type { Asistencia } from '@/types';
import { toast } from 'sonner';
import { Clock, RefreshCw, CheckCircle2, UserX, AlertTriangle, AlertCircle } from 'lucide-react';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Input } from '@/components/ui/input';

const ESTADOS_MAP: Record<string, { label: string, color: string, icon: any }> = {
    'presente': { label: 'Presente', color: 'bg-emerald-100 text-emerald-800 border-emerald-300', icon: CheckCircle2 },
    'ausente': { label: 'Ausente', color: 'bg-red-100 text-red-800 border-red-300', icon: UserX },
    'tardanza': { label: 'Tarde', color: 'bg-amber-100 text-amber-800 border-amber-300', icon: AlertTriangle },
    'salida_anticipada': { label: 'Salida Anticipada', color: 'bg-orange-100 text-orange-800 border-orange-300', icon: AlertTriangle },
    'pendiente': { label: 'Pendiente', color: 'bg-stone-100 text-stone-800 border-stone-300', icon: Clock },
    'justificado': { label: 'Falta Justificada', color: 'bg-blue-100 text-blue-800 border-blue-300', icon: CheckCircle2 },
    'no_citado': { label: 'No Citado (Retén)', color: 'bg-indigo-100 text-indigo-800 border-indigo-300', icon: AlertCircle },
    'certificado': { label: 'Certificado Médico', color: 'bg-cyan-100 text-cyan-800 border-cyan-300', icon: AlertCircle },
};

function formatDateStr(d: Date): string {
    return d.toISOString().split('T')[0];
}

function formatTimeVal(dateStr?: string | null): string {
    if (!dateStr) return '';
    try {
        const d = new Date(dateStr);
        if (isNaN(d.getTime())) return '';
        return d.toLocaleTimeString('es-UY', { hour: '2-digit', minute: '2-digit', hour12: false });
    } catch {
        return '';
    }
}

export default function SupervisorMobile() {
    const today = new Date();
    const dateStr = formatDateStr(today);

    // Auth info to possibly filter (optional for future, now we show all so they can check)
    // In the future: const user = useAuthStore(s => s.user);

    const { getAsistencias, updateAsistencia, generarPlanillaDia } = useAsistencia(dateStr, dateStr);
    const { data: asistencias = [], isLoading, refetch } = getAsistencias;

    const [isGenerating, setIsGenerating] = useState(false);

    // Auto-generate on mount to ensure today is populated
    useEffect(() => {
        async function init() {
            try {
                setIsGenerating(true);
                await generarPlanillaDia.mutateAsync(dateStr);
            } catch (e) {
                console.error("Auto generate failed", e);
            } finally {
                setIsGenerating(false);
            }
        }
        init();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [dateStr]);

    const handleActualizarEstado = async (a: Asistencia, nuevoEstado: string) => {
        try {
            const dataToUpdate: any = { estado: nuevoEstado as any };

            // Auto-fill actual times if marking present and they are null
            if (nuevoEstado === 'presente' && a.horarios) {
                if (!a.hora_entrada_registrada && a.horarios.hora_entrada) {
                    const timeStr = a.horarios.hora_entrada.substring(0, 5);
                    dataToUpdate.hora_entrada_registrada = new Date(`${a.fecha}T${timeStr}:00`).toISOString();
                }
                if (!a.hora_salida_registrada && a.horarios.hora_salida) {
                    const timeStr = a.horarios.hora_salida.substring(0, 5);
                    dataToUpdate.hora_salida_registrada = new Date(`${a.fecha}T${timeStr}:00`).toISOString();
                }
            }

            await updateAsistencia.mutateAsync({ id: a.id, data: dataToUpdate });
            toast.success(`${a.funcionarios?.profiles?.nombre} marcado como ${ESTADOS_MAP[nuevoEstado].label}`);
        } catch (error: any) {
            toast.error(error.message || 'Error al actualizar estado');
        }
    };

    const handleGuardarHora = async (a: Asistencia, field: 'hora_entrada_registrada' | 'hora_salida_registrada', timeValue: string) => {
        try {
            let finalValue = null;
            if (timeValue) {
                finalValue = new Date(`${a.fecha}T${timeValue}:00`).toISOString();
            }
            await updateAsistencia.mutateAsync({ id: a.id, data: { [field]: finalValue } as any });
            toast.success('Hora guardada');
        } catch {
            toast.error('Error al guardar hora');
        }
    };

    const handleGuardarObs = async (a: Asistencia, newVal: string) => {
        if (newVal === a.observaciones) return;
        try {
            await updateAsistencia.mutateAsync({ id: a.id, data: { observaciones: newVal } as any });
            toast.success('Observación guardada');
        } catch {
            toast.error('Error');
        }
    };

    if (isLoading || isGenerating) {
        return (
            <div className="flex flex-col items-center justify-center h-full space-y-4 py-20">
                <RefreshCw className="h-8 w-8 animate-spin text-coreops-primary" />
                <p className="text-muted-foreground font-medium">Buscando turnos de hoy...</p>
            </div>
        );
    }

    // Grouping by "Servicio"
    const byService = asistencias.reduce((acc: Record<string, Asistencia[]>, a: Asistencia) => {
        const clientName = a.horarios?.servicios?.clientes?.razon_social || 'Sin Cliente';
        const serviceName = a.horarios?.servicios?.nombre || 'General';
        const key = `${clientName} - ${serviceName}`;
        if (!acc[key]) acc[key] = [];
        acc[key].push(a);
        return acc;
    }, {});

    const sortedServiceKeys = Object.keys(byService).sort();

    return (
        <div className="space-y-6 pb-6 animate-in fade-in">
            <div className="sticky top-0 bg-background/95 backdrop-blur z-10 py-2 border-b border-border shadow-sm flex items-center justify-between mb-4 -mt-2 -mx-2 px-4">
                <div className="flex flex-col">
                    <span className="text-sm text-muted-foreground font-medium">Planilla Diaria</span>
                    <span className="text-lg font-bold text-slate-800 dark:text-slate-100 capitalize">
                        {today.toLocaleDateString('es-UY', { weekday: 'long', day: 'numeric', month: 'short' })}
                    </span>
                </div>
                <Button variant="outline" size="icon" onClick={() => refetch()} className="h-9 w-9">
                    <RefreshCw className="h-4 w-4 text-muted-foreground" />
                </Button>
            </div>

            {sortedServiceKeys.length === 0 ? (
                <Card className="p-8 text-center flex flex-col items-center justify-center space-y-3 bg-slate-50 border-dashed">
                    <Clock className="h-10 w-10 text-slate-300" />
                    <p className="text-slate-500 font-medium">No hay turnos registrados para el día de hoy.</p>
                </Card>
            ) : (
                sortedServiceKeys.map(serviceName => (
                    <div key={serviceName} className="space-y-3">
                        <div className="flex items-center gap-2 sticky top-[60px] bg-slate-100/90 dark:bg-slate-800/90 backdrop-blur z-0 py-1.5 px-3 rounded-lg border shadow-sm">
                            <span className="font-bold text-sm text-coreops-primary dark:text-blue-400">
                                {serviceName}
                            </span>
                            <span className="text-xs text-muted-foreground bg-slate-200 dark:bg-slate-700 px-2 py-0.5 rounded-full">
                                {byService[serviceName].length}
                            </span>
                        </div>

                        <div className="space-y-3 px-1">
                            {byService[serviceName].map(a => {
                                const st = ESTADOS_MAP[a.estado];
                                const Icon = st.icon;
                                return (
                                    <Card key={a.id} className="overflow-hidden shadow-sm border-slate-200">
                                        <CardContent className="p-4 space-y-3">
                                            <div className="flex justify-between items-start">
                                                <div>
                                                    <h3 className="font-bold text-slate-800 dark:text-slate-100 text-base leading-tight">
                                                        {a.funcionarios?.profiles?.nombre} {a.funcionarios?.profiles?.apellido}
                                                    </h3>
                                                    <p className="text-xs text-slate-500 font-medium mt-0.5 flex items-center gap-1">
                                                        <Clock className="h-3 w-3" />
                                                        {a.horarios?.hora_entrada?.substring(0,5)} - {a.horarios?.hora_salida?.substring(0,5)}
                                                    </p>
                                                </div>
                                                <div className={`px-2.5 py-1 rounded-md text-xs font-bold border flex items-center gap-1 ${st.color}`}>
                                                    <Icon className="h-3 w-3" />
                                                    {st.label}
                                                </div>
                                            </div>

                                            <div className="grid grid-cols-2 gap-2 mt-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                                                <div className="space-y-1">
                                                    <label className="text-[10px] uppercase font-bold text-slate-400">Estado</label>
                                                    <Select value={a.estado} onValueChange={(val) => handleActualizarEstado(a, val)}>
                                                        <SelectTrigger className="h-10 text-sm bg-slate-50 font-semibold focus:ring-1">
                                                            <SelectValue />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            {Object.entries(ESTADOS_MAP).map(([k, v]) => (
                                                                <SelectItem key={k} value={k}>{v.label}</SelectItem>
                                                            ))}
                                                        </SelectContent>
                                                    </Select>
                                                </div>
                                                <div className="space-y-1">
                                                    <label className="text-[10px] uppercase font-bold text-slate-400">Motivo / Obs</label>
                                                    <Input 
                                                        defaultValue={a.observaciones || ''} 
                                                        placeholder="Escribir..."
                                                        className="h-10 text-sm bg-slate-50"
                                                        onBlur={(e) => handleGuardarObs(a, e.target.value)}
                                                    />
                                                </div>
                                            </div>

                                            {/* Times row (only if not unassigned/pending usually, but we keep it available) */}
                                            {a.estado !== 'ausente' && a.estado !== 'justificado' && a.estado !== 'certificado' && (
                                                <div className="grid grid-cols-2 gap-2 pt-1">
                                                    <div className="space-y-1">
                                                        <label className="text-[10px] font-bold text-emerald-600/70 uppercase flex items-center gap-1"><Clock className="h-2.5 w-2.5"/> Entrada Real</label>
                                                        <Input 
                                                            type="time" 
                                                            defaultValue={formatTimeVal(a.hora_entrada_registrada)}
                                                            className="h-9 text-sm font-mono border-emerald-200 bg-emerald-50/50"
                                                            onBlur={(e) => handleGuardarHora(a, 'hora_entrada_registrada', e.target.value)}
                                                        />
                                                    </div>
                                                    <div className="space-y-1">
                                                        <label className="text-[10px] font-bold text-rose-600/70 uppercase flex items-center gap-1"><Clock className="h-2.5 w-2.5"/> Salida Real</label>
                                                        <Input 
                                                            type="time" 
                                                            defaultValue={formatTimeVal(a.hora_salida_registrada)}
                                                            className="h-9 text-sm font-mono border-rose-200 bg-rose-50/50"
                                                            onBlur={(e) => handleGuardarHora(a, 'hora_salida_registrada', e.target.value)}
                                                        />
                                                    </div>
                                                </div>
                                            )}
                                        </CardContent>
                                    </Card>
                                );
                            })}
                        </div>
                    </div>
                ))
            )}
        </div>
    );
}
